// Helper to get allowlist query based on role column existence
function getAllowlistQuery(hasRole) {
    if (hasRole) {
        return `SELECT researcher_id, name, institution_email, affiliation, active, COALESCE(role, 'researcher') as role
                FROM di_allowlist WHERE LOWER(institution_email) = $1`;
    }
    return `SELECT researcher_id, name, institution_email, affiliation, active, 'researcher' as role
            FROM di_allowlist WHERE LOWER(institution_email) = $1`;
}

// POST /api/di/access-check
// Check if email is in allowlist and whether user exists
app.post('/api/di/access-check', async (req, res) => {
    try {
        const body = req.body || {};
        const institution_email = body.institution_email;

        if (!institution_email) {
            return res.status(400).json({ error: 'Email is required' });
        }
        const emailLower = String(institution_email).toLowerCase().trim();

        // Check allowlist (handle missing role column)
        const hasRole = await checkRoleColumn();
        const allowlistResult = await pool.query(getAllowlistQuery(hasRole), [emailLower]);

        if (allowlistResult.rows.length === 0) {
            return res.json({ allowed: false, message: 'Email not in allowlist' });
        }

        const allowlistEntry = allowlistResult.rows[0];

        if (!allowlistEntry.active) {
            return res.json({ allowed: false, message: 'Account is inactive' });
        }

        // Workspace-scoped access check: if ?ws= is provided, verify membership
        const wsSlug = req.query.ws || req.headers['x-workspace-slug'] || '';
        let wsRole = null;
        if (wsSlug && wsSlug !== 'natlab') {
            const hasWu = await checkWuTable();
            if (hasWu) {
                const wsMemberCheck = await pool.query(
                    `SELECT wu.role, wu.workspace_position FROM workspace_users wu
                     JOIN workspaces w ON w.id = wu.workspace_id
                     WHERE wu.user_id = $1 AND w.slug = $2 AND wu.is_active = true`,
                    [allowlistEntry.researcher_id, wsSlug]
                );
                if (wsMemberCheck.rows.length === 0) {
                    return res.json({ allowed: false, message: 'You do not have access to this workspace' });
                }
                wsRole = wsMemberCheck.rows[0].role;
                const wsPos = (wsMemberCheck.rows[0].workspace_position || '').toLowerCase();
                // Investor users in Theralia should use the investor access flow, not standard login/register
                if (wsRole === 'investor' || wsPos === 'investor') {
                    return res.json({
                        allowed: true,
                        investor_redirect: 'access-investor.html',
                        name: allowlistEntry.name,
                        role: allowlistEntry.role
                    });
                }
            }
        }

        // Check if user already registered
        const userResult = await pool.query(
            'SELECT institution_email FROM di_users WHERE LOWER(institution_email) = $1',
            [emailLower]
        );

        const isRegistered = userResult.rows.length > 0;

        return res.json({
            allowed: true,
            next: isRegistered ? 'login' : 'register',
            name: allowlistEntry.name,
            affiliation: allowlistEntry.affiliation,
            role: allowlistEntry.role
        });

    } catch (err) {
        console.error('Access check error:', err);
        res.status(500).json({ error: 'Server error' });
    }
});

// POST /api/di/register
// Register a new user (must be in allowlist)
app.post('/api/di/register', async (req, res) => {
    try {
        const { institution_email, personal_email, password } = req.body;

        if (!institution_email || !password) {
            return res.status(400).json({ error: 'Email and password are required' });
        }

        if (password.length < 8) {
            return res.status(400).json({ error: 'Password must be at least 8 characters' });
        }

        const emailLower = institution_email.toLowerCase().trim();

        // Verify in allowlist (handle missing role column)
        const hasRole = await checkRoleColumn();
        const allowlistResult = await pool.query(getAllowlistQuery(hasRole), [emailLower]);

        if (allowlistResult.rows.length === 0) {
            return res.status(403).json({ error: 'Email not in allowlist' });
        }

        const allowlistEntry = allowlistResult.rows[0];

        if (!allowlistEntry.active) {
            return res.status(403).json({ error: 'Account is inactive' });
        }

        // Check if already registered
        const existingUser = await pool.query(
            'SELECT institution_email FROM di_users WHERE LOWER(institution_email) = $1',
            [emailLower]
        );

        if (existingUser.rows.length > 0) {
            return res.status(409).json({ error: 'User already registered' });
        }

        // Hash password
        const saltRounds = 10;
        const passwordHash = await bcrypt.hash(password, saltRounds);

        // Insert user
        await pool.query(
            `INSERT INTO di_users (institution_email, personal_email, password_hash, researcher_id, created_at)
             VALUES ($1, $2, $3, $4, CURRENT_TIMESTAMP)`,
            [emailLower, personal_email || null, passwordHash, allowlistEntry.researcher_id]
        );

        // Set session with role
        req.session.user = {
            institution_email: emailLower,
            researcher_id: allowlistEntry.researcher_id,
            name: allowlistEntry.name,
            affiliation: allowlistEntry.affiliation,
            role: allowlistEntry.role
        };

        // Determine redirect based on role and workspace context
        const wsSlug = req.query.ws || req.headers['x-workspace-slug'] || '';
        let redirectPage = 'upload.html';
        if (wsSlug && wsSlug !== 'natlab') {
            redirectPage = `portal-${wsSlug}.html`;
        } else if (allowlistEntry.role === 'pi') {
            redirectPage = 'pi-dashboard.html';
        }

        res.json({
            success: true,
            message: 'Registration successful',
            user: req.session.user,
            redirect: redirectPage
        });

    } catch (err) {
        console.error('Registration error:', err);
        res.status(500).json({ error: 'Server error' });
    }
});

// POST /api/di/login
// Login an existing user
app.post('/api/di/login', async (req, res) => {
    try {
        const { institution_email, password } = req.body;

        if (!institution_email || !password) {
            return res.status(400).json({ error: 'Email and password are required' });
        }

        const emailLower = institution_email.toLowerCase().trim();

        // Get user with allowlist info (handle missing role column)
        const hasRole = await checkRoleColumn();
        const hasAiBotCap = await checkAiBotCapCol();
        const capSelect = hasAiBotCap ? `, a.ai_bot_capabilities` : `, '{}'::text as ai_bot_capabilities`;
        const loginQuery = hasRole
            ? `SELECT u.institution_email, u.password_hash, u.researcher_id,
                      a.name, a.affiliation, a.active, COALESCE(a.role, 'researcher') as role,
                      COALESCE(u.force_password_reset, false) as force_password_reset${capSelect}
               FROM di_users u
               JOIN di_allowlist a ON u.researcher_id = a.researcher_id
               WHERE LOWER(u.institution_email) = $1`
            : `SELECT u.institution_email, u.password_hash, u.researcher_id,
                      a.name, a.affiliation, a.active, 'researcher' as role,
                      COALESCE(u.force_password_reset, false) as force_password_reset${capSelect}
               FROM di_users u
               JOIN di_allowlist a ON u.researcher_id = a.researcher_id
               WHERE LOWER(u.institution_email) = $1`;

        const result = await pool.query(loginQuery, [emailLower]);

        if (result.rows.length === 0) {
            return res.status(401).json({ error: 'Invalid credentials' });
        }

        const user = result.rows[0];

        if (!user.active) {
            return res.status(403).json({ error: 'Account is inactive' });
        }

        // Verify password
        const passwordMatch = await bcrypt.compare(password, user.password_hash);

        if (!passwordMatch) {
            return res.status(401).json({ error: 'Invalid credentials' });
        }

        // Check if password reset is required
        if (user.force_password_reset) {
            const resetWsSlug = req.query.ws || req.headers['x-workspace-slug'] || '';
            // Store info in session for password reset page
            req.session.pendingPasswordReset = {
                researcher_id: user.researcher_id,
                institution_email: user.institution_email,
                name: user.name,
                affiliation: user.affiliation,
                workspace_slug: resetWsSlug
            };
            return res.json({
                success: true,
                message: 'Password reset required',
                requirePasswordReset: true,
                redirect: 'reset-password.html'
            });
        }

        // Update last login (fire-and-forget — not user-facing, no need to block response)
        pool.query(
            'UPDATE di_users SET last_login = CURRENT_TIMESTAMP WHERE LOWER(institution_email) = $1',
            [emailLower]
        ).catch(err => console.error('[LOGIN] last_login update failed:', err.message));

        // Parse ai_bot_capabilities (JSONB comes back as object; fallback string parse)
        let aiBotCaps = {};
        try {
            if (user.ai_bot_capabilities) {
                aiBotCaps = typeof user.ai_bot_capabilities === 'string'
                    ? JSON.parse(user.ai_bot_capabilities)
                    : user.ai_bot_capabilities;
            }
        } catch (e) { aiBotCaps = {}; }

        // Set session with role
        req.session.user = {
            institution_email: user.institution_email,
            researcher_id: user.researcher_id,
            name: user.name,
            affiliation: user.affiliation,
            role: user.role,
            ai_bot_capabilities: user.role === 'ai_bot' ? aiBotCaps : {}
        };

        // Determine redirect based on role and workspace context
        const wsSlug = req.query.ws || req.headers['x-workspace-slug'] || '';
        let redirectPage = 'upload.html';
        if (wsSlug && wsSlug !== 'natlab') {
            // Workspace-specific portal redirect
            redirectPage = `portal-${wsSlug}.html`;
        } else if (user.role === 'pi' || user.role === 'ai_bot') {
            // AI_bot inherits PI-level visibility, lands on PI dashboard.
            redirectPage = 'pi-dashboard.html';
        }
        // Supervisors go to upload.html (same as researchers) but get additional supervision panel

        res.json({
            success: true,
            message: 'Login successful',
            role: user.role,
            user: req.session.user,
            redirect: redirectPage
        });

    } catch (err) {
        console.error('Login error:', err);
        res.status(500).json({ error: 'Server error' });
    }
});

// POST /api/di/complete-password-reset
// Complete a forced password reset (user sets new password)
app.post('/api/di/complete-password-reset', async (req, res) => {
    try {
        const { password } = req.body;

        // Check for pending password reset in session
        if (!req.session.pendingPasswordReset) {
            return res.status(403).json({ error: 'No pending password reset' });
        }

        if (!password || password.length < 8) {
            return res.status(400).json({ error: 'Password must be at least 8 characters' });
        }

        const { researcher_id, institution_email, name, affiliation } = req.session.pendingPasswordReset;

        // Hash new password
        const saltRounds = 10;
        const passwordHash = await bcrypt.hash(password, saltRounds);

        // Update password and clear the reset flag
        await pool.query(
            `UPDATE di_users
             SET password_hash = $1, force_password_reset = false, last_login = CURRENT_TIMESTAMP
             WHERE researcher_id = $2`,
            [passwordHash, researcher_id]
        );

        // Get user role for redirect
        const hasRole = await checkRoleColumn();
        const roleQuery = hasRole
            ? `SELECT COALESCE(role, 'researcher') as role FROM di_allowlist WHERE researcher_id = $1`
            : `SELECT 'researcher' as role FROM di_allowlist WHERE researcher_id = $1`;
        const roleResult = await pool.query(roleQuery, [researcher_id]);
        const role = roleResult.rows[0]?.role || 'researcher';

        // Determine redirect based on role and workspace context
        const resetWsSlug = req.session.pendingPasswordReset?.workspace_slug || '';

        // Clear pending reset and set normal session
        delete req.session.pendingPasswordReset;
        req.session.user = {
            institution_email,
            researcher_id,
            name,
            affiliation,
            role
        };
        let redirectPage = 'upload.html';
        if (resetWsSlug && resetWsSlug !== 'natlab') {
            redirectPage = `portal-${resetWsSlug}.html`;
        } else if (role === 'pi') {
            redirectPage = 'pi-dashboard.html';
        }

        console.log(`Password reset completed for user ${researcher_id}`);

        res.json({
            success: true,
            message: 'Password updated successfully',
            redirect: redirectPage
        });

    } catch (err) {
        console.error('Complete password reset error:', err);
        res.status(500).json({ error: 'Server error' });
    }
});

// GET /api/di/pending-reset-info
// Get info for pending password reset (for reset-password.html)
app.get('/api/di/pending-reset-info', async (req, res) => {
    if (!req.session.pendingPasswordReset) {
        return res.status(403).json({ error: 'No pending password reset' });
    }
    const pending = req.session.pendingPasswordReset;
    const resp = {
        name: pending.name,
        affiliation: pending.affiliation
    };

    // Enrich with workspace context if available
    const wsSlug = pending.workspace_slug || '';
    if (wsSlug) {
        resp.workspace_slug = wsSlug;
        try {
            const wsRow = await pool.query('SELECT name FROM workspaces WHERE slug = $1', [wsSlug]);
            if (wsRow.rows.length > 0) resp.workspace_name = wsRow.rows[0].name;
        } catch {}

        // Look up workspace position/role
        try {
            const hasWu = await checkWuTable();
            const hasPos = hasWu && await checkStartupPositionCols();
            if (hasWu) {
                const posCols = hasPos ? ', wu.workspace_position' : '';
                const r = await pool.query(
                    `SELECT wu.role${posCols} FROM workspace_users wu
                     JOIN workspaces w ON w.id = wu.workspace_id
                     WHERE wu.user_id = $1 AND w.slug = $2 AND wu.is_active = TRUE LIMIT 1`,
                    [pending.researcher_id, wsSlug]);
                if (r.rows.length > 0) {
                    resp.workspace_role = r.rows[0].role || null;
                    if (hasPos) resp.workspace_position = r.rows[0].workspace_position || null;
                }
            }
        } catch {}
    }

    res.json(resp);
});

// GET /api/di/me
// Get current user profile (includes startup position/authority for COMPANY workspaces)
app.get('/api/di/me', requireAuth, async (req, res) => {
    const base = {
        name: req.session.user.name,
        researcher_id: req.session.user.researcher_id,
        affiliation: req.session.user.affiliation,
        role: req.session.user.role || 'researcher',
        institution_email: req.session.user.institution_email
    };

    // Expose AI_bot capabilities so the frontend can gate action buttons.
    // Only meaningful when role === 'ai_bot'; empty object otherwise.
    if (req.session.user.role === 'ai_bot') {
        base.ai_bot_capabilities = req.session.user.ai_bot_capabilities || {};
    }

    // Pass through investor session markers if present
    if (req.session.user.user_type) base.user_type = req.session.user.user_type;
    if (req.session.user.access_tier) base.access_tier = req.session.user.access_tier;

    // NAT-Lab clearance profile + module access + tab overrides (for frontend tab visibility resolver)
    try {
        const hasWu = await checkWuTable();
        const hasClearance = hasWu && await checkWuClearanceCols();
        const hasModuleAccess = hasWu && await checkModuleAccessCol();
        const hasTabVis = hasWu && await checkTabVisibilityCol();
        if (hasWu) {
            const cpCol = hasClearance ? ', wu.clearance_profile' : '';
            const maCol = hasModuleAccess ? ', wu.module_access_json' : '';
            const tvCol = hasTabVis ? ', wu.tab_visibility_json' : '';
            const result = await pool.query(
                `SELECT wu.role${cpCol}${maCol}${tvCol}
                 FROM workspace_users wu
                 JOIN workspaces w ON w.id = wu.workspace_id
                 WHERE wu.user_id = $1 AND w.slug = 'natlab' AND wu.is_active = TRUE`,
                [req.session.user.researcher_id]
            );
            if (result.rows.length > 0) {
                const row = result.rows[0];
                if (hasClearance && row.clearance_profile) base.clearance_profile = row.clearance_profile;
                if (hasModuleAccess && row.module_access_json) base.module_access_json = row.module_access_json;
                if (hasTabVis && row.tab_visibility_json) base.tab_visibility_json = row.tab_visibility_json;
            }
        }
    } catch (err) {
        console.error('[ME] NATLAB clearance/module access error:', err.message);
    }

    // Enrich with startup position if requesting from a COMPANY workspace
    const wsSlug = req.query.workspace || req.headers['x-workspace-slug'] || '';
    if (wsSlug && wsSlug !== 'natlab') {
        try {
            const hasWu = await checkWuTable();
            const hasPos = hasWu && await checkStartupPositionCols();
            if (hasWu) {
                const posCols = hasPos ? ', wu.workspace_position, wu.is_workspace_master, wu.can_manage_users, wu.can_manage_workspace, wu.can_manage_portal, wu.view_management_tab' : '';
                // Check if clearance_config column exists (added by governance migration)
                let ccCol = '';
                try {
                    const ccCheck = await pool.query(`SELECT EXISTS(SELECT 1 FROM information_schema.columns WHERE table_name='workspace_users' AND column_name='clearance_config') AS ok`);
                    if (ccCheck.rows[0]?.ok) ccCol = ', wu.clearance_config';
                } catch {}
                const result = await pool.query(
                    `SELECT wu.role${posCols}, wu.investor_tab_permissions, wu.custom_position_title${ccCol}
                     FROM workspace_users wu
                     JOIN workspaces w ON w.id = wu.workspace_id
                     WHERE wu.user_id = $1 AND w.slug = $2 AND wu.is_active = TRUE`,
                    [req.session.user.researcher_id, wsSlug]
                );
                if (result.rows.length > 0) {
                    const row = result.rows[0];
                    base.role = row.role || base.role;
                    if (hasPos) {
                        base.workspace_position = row.workspace_position || null;
                        base.custom_position_title = row.custom_position_title || null;
                        // Authority flags — internal, never shown in role display
                        base._authority = {
                            is_workspace_master: row.is_workspace_master || false,
                            can_manage_users: row.can_manage_users || false,
                            can_manage_workspace: row.can_manage_workspace || false,
                            can_manage_portal: row.can_manage_portal || false,
                            view_management_tab: row.view_management_tab || false
                        };
                    }
                    // Investor tab permissions (for investor-role users)
                    if (row.investor_tab_permissions) {
                        base.investor_tab_permissions = row.investor_tab_permissions;
                    }
                    // Governance clearance config — merge stored overrides with position defaults
                    const pos = (row.workspace_position || '').toLowerCase();
                    const defaults = GOVERNANCE_DEFAULTS[pos] || {};
                    base.clearance_config = { ...defaults, ...(row.clearance_config || {}) };
                    // CSO always gets full clearance regardless of stored config
                    if (pos === 'cso') base.clearance_config = GOVERNANCE_DEFAULTS.cso;
                }
            }
        } catch (err) {
            console.error('[ME] Startup position lookup error:', err.message);
        }
    }

    res.json(base);
});

// GET /api/di/effective-access
// Phase 1.4: Compute effective access for the current user in a workspace (default: natlab)
app.get('/api/di/effective-access', requireAuth, async (req, res) => {
    try {
        const user = req.session.user;
        const wsSlug = req.query.workspace || 'natlab';

        const hasWu = await checkWuTable();
        const hasClearance = await checkWuClearanceCols();
        const hasModuleAccess = await checkModuleAccessCol();

        let clearance_profile = 'standard';
        let membership_class = 'core';
        let module_access_json = null;

        if (hasWu && hasClearance) {
            const moduleCol = hasModuleAccess ? ', wu.module_access_json' : '';
            const result = await pool.query(
                `SELECT wu.clearance_profile, wu.membership_class ${moduleCol}
                 FROM workspace_users wu
                 JOIN workspaces w ON w.id = wu.workspace_id
                 WHERE wu.user_id = $1 AND w.slug = $2`,
                [user.researcher_id, wsSlug]
            );
            if (result.rows.length > 0) {
                clearance_profile = result.rows[0].clearance_profile || 'standard';
                membership_class = result.rows[0].membership_class || 'core';
                module_access_json = hasModuleAccess ? result.rows[0].module_access_json : null;
            }
        }

        const access = computeEffectiveAccess({
            role: user.role,
            affiliation: user.affiliation,
            clearance_profile,
            membership_class,
            module_access_json
        });

        res.json({
            success: true,
            researcher_id: user.researcher_id,
            role: user.role,
            affiliation: user.affiliation,
            clearance_profile,
            membership_class,
            access
        });
    } catch (err) {
        console.error('Effective access error:', err);
        res.status(500).json({ error: 'Server error' });
    }
});

