// GET /api/di/lab-files-enriched — Performance-bounded with association counts
app.get('/api/di/lab-files-enriched', requirePIRead, async (req, res) => {
    try {
        const months = Math.min(Math.max(parseInt(req.query.months) || 12, 6), 60);
        const hasAssoc = await checkAssociationsTable();
        const hasLegacy = await checkLegacyColumns();
        const hasVC = await checkVisionColumns();
        const delFilt = hasVC ? ' AND deleted_at IS NULL' : '';

        const legacyCols = hasLegacy
            ? `, s.record_origin, s.original_created_at, s.legacy_pack_id,
                 s.legacy_pack_title, s.legacy_pack_context_type, s.legacy_pack_submitted_at`
            : `, NULL as record_origin, NULL as original_created_at, NULL as legacy_pack_id,
                 NULL as legacy_pack_title, NULL as legacy_pack_context_type, NULL as legacy_pack_submitted_at`;

        const workspaceId = req.workspace.id;

        // Implementation note: structured for easy future extension with ?researcher_id=
        const conditions = ['s.created_at >= NOW() - make_interval(months => $1)', "s.status != 'DISCARDED'", 's.workspace_id = $2'];
        const params = [months, workspaceId];

        const whereClause = conditions.length ? 'WHERE ' + conditions.join(' AND ') : '';

        const query = hasAssoc
            ? `SELECT s.submission_id, s.researcher_id, s.original_filename, s.file_type,
                      s.status, s.created_at, s.signed_at, s.ai_review,
                      s.pi_dragon_seal,
                      s.r2_object_key,
                      a.name as researcher_name, a.affiliation,
                      COALESCE(sop_c.cnt, 0)::int as linked_sop_count,
                      COALESCE(pres_c.cnt, 0)::int as linked_pres_count
                      ${legacyCols}
               FROM di_submissions s
               LEFT JOIN di_allowlist a ON s.researcher_id = a.researcher_id
               LEFT JOIN (SELECT source_id, COUNT(*) as cnt FROM di_file_associations
                          WHERE link_type='SOP'${delFilt} GROUP BY source_id) sop_c
                          ON s.submission_id = sop_c.source_id
               LEFT JOIN (SELECT source_id, COUNT(*) as cnt FROM di_file_associations
                          WHERE link_type='PRESENTATION'${delFilt} GROUP BY source_id) pres_c
                          ON s.submission_id = pres_c.source_id
               ${whereClause}
               ORDER BY s.created_at DESC`
            : `SELECT s.submission_id, s.researcher_id, s.original_filename, s.file_type,
                      s.status, s.created_at, s.signed_at, s.ai_review,
                      s.pi_dragon_seal,
                      s.r2_object_key,
                      a.name as researcher_name, a.affiliation,
                      0 as linked_sop_count, 0 as linked_pres_count
                      ${legacyCols}
               FROM di_submissions s
               LEFT JOIN di_allowlist a ON s.researcher_id = a.researcher_id
               ${whereClause}
               ORDER BY s.created_at DESC`;

        const result = await pool.query(query, params);
        const files = result.rows.map(r => ({ ...r, access_mode: 'owned' }));

        // Append active shared files (migration 035)
        if (await checkFileSharesTable()) {
            const sharedResult = await pool.query(`
                SELECT s.submission_id, fs.recipient_researcher_id as researcher_id,
                       s.original_filename, s.file_type, s.status,
                       fs.shared_at as created_at, s.signed_at, s.ai_review,
                       s.pi_dragon_seal, s.r2_object_key,
                       a.name as researcher_name, ra.affiliation,
                       0 as linked_sop_count, 0 as linked_pres_count,
                       fs.shared_by, fs.owner_researcher_id
                       ${hasLegacy ? ", NULL as record_origin, NULL as original_created_at, NULL as legacy_pack_id, NULL as legacy_pack_title, NULL as legacy_pack_context_type, NULL as legacy_pack_submitted_at" : ", NULL as record_origin, NULL as original_created_at, NULL as legacy_pack_id, NULL as legacy_pack_title, NULL as legacy_pack_context_type, NULL as legacy_pack_submitted_at"}
                FROM di_file_shares fs
                JOIN di_submissions s ON s.submission_id = fs.submission_id
                LEFT JOIN di_allowlist a ON fs.recipient_researcher_id = a.researcher_id
                LEFT JOIN di_allowlist ra ON fs.recipient_researcher_id = ra.researcher_id
                WHERE fs.is_active = TRUE AND s.status != 'DISCARDED'
                  AND fs.recipient_researcher_id != fs.owner_researcher_id
                  AND fs.shared_at >= NOW() - make_interval(months => $1)
                  AND fs.workspace_id = $2 AND s.workspace_id = $2
                ORDER BY fs.shared_at DESC
            `, [months, workspaceId]);
            for (const row of sharedResult.rows) {
                row.access_mode = 'shared';
                files.push(row);
            }
        }

        res.json({ success: true, months_used: months, files });
    } catch (err) {
        console.error('Get enriched lab files error:', err);
        res.status(500).json({ error: 'Server error' });
    }
});

