// Record investor visit (called from investor portal on load)
app.post('/api/investor/record-visit', requireAuth, async (req, res) => {
    try {
        const user = req.session.user;
        const ws = req.query.workspace || req.body.workspace || 'theralia';
        // Only record for investor-role users
        const wsUser = await pool.query(
            `SELECT role, workspace_position FROM workspace_users wu
             JOIN workspaces w ON wu.workspace_id = w.id
             WHERE wu.user_id = $1 AND w.slug = $2`,
            [user.researcher_id, ws]
        );
        const wsRole = wsUser.rows[0]?.role;
        if (wsRole !== 'investor') {
            return res.json({ ok: true, recorded: false });
        }
        // Check if table exists
        const tbl = await pool.query(`SELECT to_regclass('public.investor_portal_visits') AS t`);
        if (!tbl.rows[0]?.t) {
            return res.json({ ok: true, recorded: false });
        }
        // Upsert visit
        await pool.query(
            `INSERT INTO investor_portal_visits (workspace_id, researcher_id, investor_name, investor_email, investor_company)
             VALUES ($1, $2, $3, $4, $5)
             ON CONFLICT (workspace_id, researcher_id) DO UPDATE SET
                last_seen_at = NOW(),
                visit_count = investor_portal_visits.visit_count + 1,
                investor_name = COALESCE(EXCLUDED.investor_name, investor_portal_visits.investor_name),
                investor_email = COALESCE(EXCLUDED.investor_email, investor_portal_visits.investor_email)`,
            [ws, user.researcher_id, user.name, user.institution_email, req.body.company || null]
        );
        res.json({ ok: true, recorded: true });
    } catch (err) {
        console.error('[INVESTOR-VISIT] Error:', err.message);
        res.json({ ok: true, recorded: false });
    }
});

// List investor visitors (founder-only, for InvestRoom)
app.get('/api/investor/visitors', requireAuth, async (req, res) => {
    try {
        const user = req.session.user;
        const ws = req.query.workspace || 'theralia';
        // Check founder access
        const wsUser = await pool.query(
            `SELECT role, workspace_position FROM workspace_users wu
             JOIN workspaces w ON wu.workspace_id = w.id
             WHERE wu.user_id = $1 AND w.slug = $2`,
            [user.researcher_id, ws]
        );
        const pos = (wsUser.rows[0]?.workspace_position || '').toLowerCase();
        const role = wsUser.rows[0]?.role;
        if (!['ceo', 'cso', 'founder'].includes(pos) && role !== 'founder') {
            return res.status(403).json({ error: 'Access denied' });
        }
        // Check table exists
        const tbl = await pool.query(`SELECT to_regclass('public.investor_portal_visits') AS t`);
        if (!tbl.rows[0]?.t) {
            return res.json({ visitors: [] });
        }
        const hasCodeTable = await checkInvCodeTable();
        const codeCols = hasCodeTable
            ? `, iac.last_renewed_at, iac.renewal_count, iac.last_login_at as code_last_login`
            : `, NULL as last_renewed_at, 0 as renewal_count, NULL as code_last_login`;
        const codeJoin = hasCodeTable
            ? `LEFT JOIN investor_access_codes iac ON iac.researcher_id = v.researcher_id AND iac.workspace_id = v.workspace_id`
            : '';
        const result = await pool.query(
            `SELECT v.researcher_id, v.investor_name, v.investor_email, v.investor_company,
                    v.last_seen_at, v.visit_count, v.created_at
                    ${codeCols}
             FROM investor_portal_visits v
             ${codeJoin}
             WHERE v.workspace_id = $1
             ORDER BY v.last_seen_at DESC`,
            [ws]
        );
        res.json({ visitors: result.rows });
    } catch (err) {
        console.error('[INVESTOR-VISITORS] Error:', err.message);
        res.status(500).json({ error: 'Failed to load visitors' });
    }
});

// InvestRoom KPI summary (founder-only)
app.get('/api/investor/kpis', requireAuth, async (req, res) => {
    try {
        const user = req.session.user;
        const ws = req.query.workspace || 'theralia';
        // Founder access check
        const wsUser = await pool.query(
            `SELECT role, workspace_position FROM workspace_users wu
             JOIN workspaces w ON wu.workspace_id = w.id
             WHERE wu.user_id = $1 AND w.slug = $2`,
            [user.researcher_id, ws]
        );
        const pos = (wsUser.rows[0]?.workspace_position || '').toLowerCase();
        const role = wsUser.rows[0]?.role;
        if (!['ceo', 'cso', 'founder'].includes(pos) && role !== 'founder') {
            return res.status(403).json({ error: 'Access denied' });
        }

        const result = { all: { views: 0, avgTime: '\u2014', docs: 0, meetings: 0, videoPlays: 0, watchTime: '\u2014', portalTime: '\u2014' } };

        // Visit data
        const visitsTbl = await pool.query(`SELECT to_regclass('public.investor_portal_visits') AS t`);
        if (visitsTbl.rows[0]?.t) {
            const visits = await pool.query(
                `SELECT researcher_id, investor_email, visit_count FROM investor_portal_visits WHERE workspace_id = $1`, [ws]
            );
            let totalViews = 0;
            for (const v of visits.rows) {
                totalViews += v.visit_count;
                result[v.researcher_id] = {
                    views: v.visit_count, avgTime: '\u2014', docs: 0, meetings: 0, videoPlays: 0, watchTime: '\u2014', portalTime: '\u2014'
                };
            }
            result.all.views = totalViews;
            if (visits.rows.length > 0) {
                result.all.avgTime = Math.round(totalViews / visits.rows.length) + ' visits/inv'; // visit-based metric, not session timing
            }
        }

        // Meeting data
        const meetTbl = await pool.query(`SELECT to_regclass('public.investor_meeting_bookings') AS t`);
        if (meetTbl.rows[0]?.t) {
            const meetings = await pool.query(
                `SELECT investor_email, COUNT(*) as cnt FROM investor_meeting_bookings
                 WHERE workspace_id = $1 AND status = 'booked'
                 GROUP BY investor_email`, [ws]
            );
            let totalMeetings = 0;
            for (const m of meetings.rows) {
                totalMeetings += parseInt(m.cnt);
                // Match by email to researcher_id
                for (const rid in result) {
                    if (rid !== 'all' && result[rid]) {
                        // Check if this email matches via visits table
                    }
                }
            }
            result.all.meetings = totalMeetings;
            // Per-investor meeting count via email match
            if (visitsTbl.rows[0]?.t) {
                const emailMap = await pool.query(
                    `SELECT researcher_id, investor_email FROM investor_portal_visits WHERE workspace_id = $1`, [ws]
                );
                const ridByEmail = {};
                for (const row of emailMap.rows) {
                    if (row.investor_email) ridByEmail[row.investor_email.toLowerCase()] = row.researcher_id;
                }
                for (const m of meetings.rows) {
                    const rid = ridByEmail[(m.investor_email || '').toLowerCase()];
                    if (rid && result[rid]) {
                        result[rid].meetings = parseInt(m.cnt);
                    }
                }
            }
        }

        // Activity-based metrics (docs, video plays, watch time)
        if (await checkInvestorActivityTable()) {
            const actStats = await pool.query(
                `SELECT researcher_id, activity_type, COUNT(*) as cnt,
                        SUM(COALESCE(duration_seconds, 0)) as total_secs
                 FROM investor_portal_activity
                 WHERE workspace_id = $1
                 GROUP BY researcher_id, activity_type`, [ws]
            );
            let allDocs = 0, allPlays = 0, allWatch = 0;
            for (const row of actStats.rows) {
                const rid = row.researcher_id;
                const cnt = parseInt(row.cnt);
                const secs = parseInt(row.total_secs) || 0;
                if (!result[rid]) {
                    result[rid] = { views: 0, avgTime: '\u2014', docs: 0, meetings: 0, videoPlays: 0, watchTime: '\u2014', portalTime: '\u2014' };
                }
                if (row.activity_type === 'doc_opened') {
                    result[rid].docs = (result[rid].docs || 0) + cnt;
                    allDocs += cnt;
                } else if (row.activity_type === 'video_play') {
                    result[rid].videoPlays = (result[rid].videoPlays || 0) + cnt;
                    allPlays += cnt;
                } else if (row.activity_type === 'video_watch') {
                    const prevSecs = parseInt(result[rid]._watchSecs) || 0;
                    result[rid]._watchSecs = prevSecs + secs;
                    allWatch += secs;
                }
            }
            result.all.docs = allDocs;
            result.all.videoPlays = allPlays;
            if (allWatch > 0) {
                result.all.watchTime = allWatch >= 60 ? Math.round(allWatch / 60) + ' min' : allWatch + 's';
            }
            // Format per-investor watch time
            for (const rid in result) {
                if (rid !== 'all' && result[rid]._watchSecs) {
                    const s = result[rid]._watchSecs;
                    result[rid].watchTime = s >= 60 ? Math.round(s / 60) + ' min' : s + 's';
                    delete result[rid]._watchSecs;
                }
            }
        }

        // Portal session time
        if (await checkInvestorSessionsTable()) {
            // Close stale sessions (no heartbeat for > inactivity threshold)
            await pool.query(
                `UPDATE investor_portal_sessions
                 SET ended_at = last_seen_at,
                     duration_seconds = GREATEST(EXTRACT(EPOCH FROM (last_seen_at - started_at))::int, 0),
                     end_reason = 'inactivity'
                 WHERE workspace_id = $1 AND ended_at IS NULL
                   AND last_seen_at < NOW() - INTERVAL '${INVESTOR_SESSION_INACTIVITY_SEC} seconds'`,
                [ws]
            );
            const sessions = await pool.query(
                `SELECT researcher_id, SUM(
                    CASE WHEN ended_at IS NOT NULL THEN duration_seconds
                         ELSE GREATEST(EXTRACT(EPOCH FROM (NOW() - started_at))::int, 0)
                    END
                 ) as total_secs
                 FROM investor_portal_sessions
                 WHERE workspace_id = $1
                 GROUP BY researcher_id`, [ws]
            );
            let allPortalSecs = 0;
            for (const s of sessions.rows) {
                const secs = parseInt(s.total_secs) || 0;
                allPortalSecs += secs;
                if (result[s.researcher_id]) {
                    result[s.researcher_id].portalTime = secs >= 3600 ? Math.floor(secs / 3600) + 'h ' + Math.round((secs % 3600) / 60) + 'm' : secs >= 60 ? Math.round(secs / 60) + 'm' : secs + 's';
                }
            }
            result.all.portalTime = allPortalSecs >= 3600 ? Math.floor(allPortalSecs / 3600) + 'h ' + Math.round((allPortalSecs % 3600) / 60) + 'm' : allPortalSecs >= 60 ? Math.round(allPortalSecs / 60) + 'm' : allPortalSecs > 0 ? allPortalSecs + 's' : '\u2014';
        }

        res.json({ kpis: result });
    } catch (err) {
        console.error('[INVESTOR-KPIS] Error:', err.message);
        res.status(500).json({ error: 'Failed to load KPIs' });
    }
});

