let _investorActivityTableExists = null;
async function checkInvestorActivityTable() {
    if (_investorActivityTableExists !== null) return _investorActivityTableExists;
    try {
        const r = await pool.query(`SELECT to_regclass('public.investor_portal_activity') AS t`);
        _investorActivityTableExists = !!r.rows[0]?.t;
    } catch { _investorActivityTableExists = false; }
    return _investorActivityTableExists;
}

// Record investor activity (authenticated investors only)
app.post('/api/investor/record-activity', requireAuth, async (req, res) => {
    try {
        if (!(await checkInvestorActivityTable())) return res.json({ ok: true, recorded: false });
        const user = req.session.user;
        const { activity_type, content_key, content_title, duration_seconds, workspace } = req.body;
        const ws = workspace || 'theralia';
        const validTypes = ['doc_opened', 'video_play', 'video_watch', 'glp_vision_opened'];
        if (!activity_type || !validTypes.includes(activity_type)) {
            return res.status(400).json({ error: 'Invalid activity_type' });
        }
        await pool.query(
            `INSERT INTO investor_portal_activity (workspace_id, researcher_id, investor_email, activity_type, content_key, content_title, duration_seconds)
             VALUES ($1, $2, $3, $4, $5, $6, $7)`,
            [ws, user.researcher_id, user.institution_email, activity_type, content_key || null, content_title || null, duration_seconds || null]
        );
        res.json({ ok: true, recorded: true });
    } catch (err) {
        console.error('[INVESTOR-ACTIVITY] Error:', err.message);
        res.json({ ok: true, recorded: false });
    }
});

// Investor activity feed + content intelligence (founder-only)
app.get('/api/investor/activity', requireAuth, async (req, res) => {
    try {
        const user = req.session.user;
        const ws = req.query.workspace || 'theralia';
        const investorId = req.query.investor || null;
        // Founder access check
        const wsUser = await pool.query(
            `SELECT role, workspace_position FROM workspace_users wu
             JOIN workspaces w ON wu.workspace_id = w.id
             WHERE wu.user_id = $1 AND w.slug = $2`,
            [user.researcher_id, ws]
        );
        const pos = (wsUser.rows[0]?.workspace_position || '').toLowerCase();
        const role = wsUser.rows[0]?.role;
        if (!['ceo', 'cso', 'founder'].includes(pos) && role !== 'founder') {
            return res.status(403).json({ error: 'Access denied' });
        }
        if (!(await checkInvestorActivityTable())) {
            return res.json({ feed: [], content: [] });
        }

        // Recent activity feed (last 20)
        let feedQuery, feedParams;
        if (investorId && investorId !== 'all') {
            feedQuery = `SELECT a.activity_type, a.content_key, a.content_title, a.duration_seconds, a.created_at,
                                v.investor_name, v.investor_email
                         FROM investor_portal_activity a
                         LEFT JOIN investor_portal_visits v ON v.researcher_id = a.researcher_id AND v.workspace_id = a.workspace_id
                         WHERE a.workspace_id = $1 AND a.researcher_id = $2
                         ORDER BY a.created_at DESC LIMIT 20`;
            feedParams = [ws, investorId];
        } else {
            feedQuery = `SELECT a.activity_type, a.content_key, a.content_title, a.duration_seconds, a.created_at,
                                v.investor_name, v.investor_email
                         FROM investor_portal_activity a
                         LEFT JOIN investor_portal_visits v ON v.researcher_id = a.researcher_id AND v.workspace_id = a.workspace_id
                         WHERE a.workspace_id = $1
                         ORDER BY a.created_at DESC LIMIT 20`;
            feedParams = [ws];
        }
        const feedRows = await pool.query(feedQuery, feedParams);

        // Content intelligence — top opened content
        let contentQuery, contentParams;
        if (investorId && investorId !== 'all') {
            contentQuery = `SELECT content_title, content_key, activity_type, COUNT(*) as cnt,
                                   SUM(COALESCE(duration_seconds, 0)) as total_seconds
                            FROM investor_portal_activity
                            WHERE workspace_id = $1 AND researcher_id = $2 AND content_title IS NOT NULL
                            GROUP BY content_title, content_key, activity_type
                            ORDER BY cnt DESC LIMIT 8`;
            contentParams = [ws, investorId];
        } else {
            contentQuery = `SELECT content_title, content_key, activity_type, COUNT(*) as cnt,
                                   SUM(COALESCE(duration_seconds, 0)) as total_seconds
                            FROM investor_portal_activity
                            WHERE workspace_id = $1 AND content_title IS NOT NULL
                            GROUP BY content_title, content_key, activity_type
                            ORDER BY cnt DESC LIMIT 8`;
            contentParams = [ws];
        }
        const contentRows = await pool.query(contentQuery, contentParams);

        res.json({
            feed: feedRows.rows,
            content: contentRows.rows
        });
    } catch (err) {
        console.error('[INVESTOR-ACTIVITY] Feed error:', err.message);
        res.status(500).json({ error: 'Failed' });
    }
});

// =====================================================
// INVESTOR PORTAL SESSIONS
// =====================================================

const INVESTOR_SESSION_INACTIVITY_SEC = 300; // 5 minutes

let _investorSessionsTableExists = null;
async function checkInvestorSessionsTable() {
    if (_investorSessionsTableExists !== null) return _investorSessionsTableExists;
    try {
        const r = await pool.query(`SELECT to_regclass('public.investor_portal_sessions') AS t`);
        _investorSessionsTableExists = !!r.rows[0]?.t;
    } catch { _investorSessionsTableExists = false; }
    return _investorSessionsTableExists;
}

// Start or resume session
app.post('/api/investor/session-start', requireAuth, async (req, res) => {
    try {
        if (!(await checkInvestorSessionsTable())) return res.json({ ok: true, session_id: null });
        const user = req.session.user;
        const ws = req.body.workspace || 'theralia';
        // Close any stale open sessions for this user (inactivity)
        await pool.query(
            `UPDATE investor_portal_sessions
             SET ended_at = last_seen_at,
                 duration_seconds = GREATEST(EXTRACT(EPOCH FROM (last_seen_at - started_at))::int, 0),
                 end_reason = 'inactivity'
             WHERE workspace_id = $1 AND researcher_id = $2 AND ended_at IS NULL`,
            [ws, user.researcher_id]
        );
        // Create new session
        const ins = await pool.query(
            `INSERT INTO investor_portal_sessions (workspace_id, researcher_id, investor_email)
             VALUES ($1, $2, $3) RETURNING id`,
            [ws, user.researcher_id, user.institution_email]
        );
        res.json({ ok: true, session_id: ins.rows[0].id });
    } catch (err) {
        console.error('[INVESTOR-SESSION] Start error:', err.message);
        res.json({ ok: true, session_id: null });
    }
});

// Heartbeat
app.post('/api/investor/session-heartbeat', requireAuth, async (req, res) => {
    try {
        if (!(await checkInvestorSessionsTable())) return res.json({ ok: true });
        const sid = req.body.session_id;
        if (!sid) return res.json({ ok: true });
        await pool.query(
            `UPDATE investor_portal_sessions SET last_seen_at = NOW() WHERE id = $1 AND ended_at IS NULL`,
            [sid]
        );
        res.json({ ok: true });
    } catch (err) {
        res.json({ ok: true });
    }
});

// Finalize session
// No requireAuth — sendBeacon doesn't reliably send cookies; session_id acts as token
app.post('/api/investor/session-end', async (req, res) => {
    try {
        if (!(await checkInvestorSessionsTable())) return res.json({ ok: true });
        const sid = req.body.session_id;
        const reason = req.body.reason || 'close';
        if (!sid) return res.json({ ok: true });
        await pool.query(
            `UPDATE investor_portal_sessions
             SET ended_at = NOW(),
                 duration_seconds = GREATEST(EXTRACT(EPOCH FROM (NOW() - started_at))::int, 0),
                 end_reason = $2
             WHERE id = $1 AND ended_at IS NULL`,
            [sid, ['logout', 'inactivity', 'close'].includes(reason) ? reason : 'close']
        );
        res.json({ ok: true });
    } catch (err) {
        res.json({ ok: true });
    }
});

// =====================================================
// END INVESTOR PORTAL SESSIONS
// =====================================================

// =====================================================
// INVESTROOM PHASE UPLOADS (CSO-only)
// =====================================================

// Cached existence check for investroom tables
let _irTablesOk = null;
async function checkIrTables() {
    if (_irTablesOk !== null) return _irTablesOk;
    try {
        const r = await pool.query(
            `SELECT EXISTS(SELECT 1 FROM information_schema.tables WHERE table_name='investroom_phase_boxes') AS ok`
        );
        _irTablesOk = r.rows[0]?.ok || false;
    } catch { _irTablesOk = false; }
    return _irTablesOk;
}

// Cached existence check for phase mirror columns (migration 057)
let _irMirrorCols = null;
async function checkIrMirrorCols() {
    if (_irMirrorCols !== null) return _irMirrorCols;
    try {
        const r = await pool.query(
            `SELECT EXISTS(SELECT 1 FROM information_schema.columns WHERE table_name='investroom_phase_boxes' AND column_name='figure_label') AS ok`
        );
        _irMirrorCols = r.rows[0]?.ok || false;
    } catch { _irMirrorCols = false; }
    return _irMirrorCols;
}

// Multer for InvestRoom box file uploads
const irBoxUpload = multer({
    storage: multer.memoryStorage(),
    limits: { fileSize: 20 * 1024 * 1024 },
    fileFilter: (req, file, cb) => {
        const allowed = ['application/pdf', 'image/png', 'image/jpeg', 'image/gif',
            'application/vnd.openxmlformats-officedocument.presentationml.presentation',
            'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'];
        cb(null, allowed.includes(file.mimetype));
    }
});

// GET /api/investroom/boxes?phase=1 — List boxes (+ files) for a phase
app.get('/api/investroom/boxes', requireAuth, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.json({ boxes: [] });
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.json({ boxes: [] });
        const phase = parseInt(req.query.phase, 10);
        if (!phase || phase < 1 || phase > 4) return res.status(400).json({ error: 'Invalid phase' });

        // Check if review columns exist (migration 056)
        let reviewCols = '';
        try {
            const rc = await pool.query(`SELECT EXISTS(SELECT 1 FROM information_schema.columns WHERE table_name='investroom_phase_box_files' AND column_name='review_status') AS ok`);
            if (rc.rows[0]?.ok) reviewCols = ", 'review_status', f.review_status, 'reviewed_by', f.reviewed_by, 'reviewed_at', f.reviewed_at";
        } catch {}

        // Check for phase mirror columns (migration 057)
        const hasMirror = await checkIrMirrorCols();
        const mirrorSelect = hasMirror ? ', b.figure_label, b.slot_type, b.layout_width' : '';

        const boxes = await pool.query(
            `SELECT b.id, b.phase_number, b.title, b.box_type, b.description, b.order_index, b.created_at${mirrorSelect},
                    COALESCE(json_agg(json_build_object(
                        'id', f.id, 'file_name', f.file_name, 'mime_type', f.mime_type,
                        'file_size', f.file_size, 'created_at', f.created_at${reviewCols}
                    ) ORDER BY f.created_at) FILTER (WHERE f.id IS NOT NULL), '[]') AS files
             FROM investroom_phase_boxes b
             LEFT JOIN investroom_phase_box_files f ON f.box_id = b.id
             WHERE b.workspace_id = $1 AND b.phase_number = $2
             GROUP BY b.id
             ORDER BY b.order_index, b.created_at`,
            [wsId, phase]
        );
        res.json({ boxes: boxes.rows });
    } catch (err) {
        console.error('[IR-BOXES] List error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// POST /api/investroom/boxes — Create a box (CSO only)
app.post('/api/investroom/boxes', requireCSO, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.status(404).json({ error: 'Workspace not found' });
        const { phase_number, title, box_type, description, figure_label, slot_type, layout_width } = req.body;
        if (!phase_number || !title || !box_type) return res.status(400).json({ error: 'Missing required fields' });
        const validTypes = ['publication','sop','data','figure','deck','document'];
        if (!validTypes.includes(box_type)) return res.status(400).json({ error: 'Invalid box_type' });
        const pn = parseInt(phase_number, 10);
        if (pn < 1 || pn > 4) return res.status(400).json({ error: 'Invalid phase_number' });

        // Get next order_index
        const maxOrd = await pool.query(
            `SELECT COALESCE(MAX(order_index), -1) + 1 AS next FROM investroom_phase_boxes WHERE workspace_id = $1 AND phase_number = $2`,
            [wsId, pn]
        );

        const hasMirror = await checkIrMirrorCols();
        const mirrorCols = hasMirror ? ', figure_label, slot_type, layout_width' : '';
        const mirrorVals = hasMirror ? ', $8, $9, $10' : '';
        const params = [wsId, pn, title.trim(), box_type, (description || '').trim() || null, maxOrd.rows[0].next, req.session.user.researcher_id];
        if (hasMirror) {
            params.push((figure_label || '').trim() || null);
            params.push(slot_type === 'data' || slot_type === 'sop' ? slot_type : null);
            params.push(layout_width === 'half' ? 'half' : 'full');
        }
        const result = await pool.query(
            `INSERT INTO investroom_phase_boxes (workspace_id, phase_number, title, box_type, description, order_index, created_by${mirrorCols})
             VALUES ($1, $2, $3, $4, $5, $6, $7${mirrorVals}) RETURNING *`,
            params
        );
        console.log(`[IR-BOXES] Box created: ${result.rows[0].id} phase=${pn} by ${req.session.user.researcher_id}`);
        res.json({ box: result.rows[0] });
    } catch (err) {
        console.error('[IR-BOXES] Create error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// POST /api/investroom/boxes/ensure-defaults — Lazy-create default boxes for a workspace (CSO only)
const IR_DEFAULT_BOXES = [
    { phase: 1, title: 'Executive Summary', box_type: 'document', description: 'Short introduction to Theralia, its rationale, and translational vision.', order: 0 },
    { phase: 1, title: 'Pitch Deck', box_type: 'deck', description: 'Company overview, platform logic, and strategic opportunity.', order: 1 },
    { phase: 1, title: 'Background Papers', box_type: 'publication', description: 'Background literature and foundational papers.', order: 2 },
    { phase: 2, title: 'Platform Overview', box_type: 'document', description: 'Technical overview of the Theralia platform and delivery approach.', order: 0 },
    { phase: 2, title: 'Mechanism Figures', box_type: 'figure', description: 'Key figures illustrating the mechanism of action.', order: 1 },
    { phase: 2, title: 'Supporting Data', box_type: 'data', description: 'Experimental datasets supporting the technology.', order: 2 },
    { phase: 3, title: 'Publication', box_type: 'publication', description: 'Peer-reviewed publications and proof-of-concept studies.', order: 0 },
    { phase: 3, title: 'Validation Data', box_type: 'data', description: 'In vivo and in vitro validation datasets.', order: 1 },
    { phase: 3, title: 'SOP', box_type: 'sop', description: 'Standard operating procedures for experimental workflows.', order: 2 },
    { phase: 3, title: 'GLP Figures', box_type: 'figure', description: 'GLP-compliant figures and structured data visualizations.', order: 3 },
    { phase: 4, title: 'IP Material', box_type: 'document', description: 'Patent filings, IP portfolio summaries, and protection strategy.', order: 0 },
    { phase: 4, title: 'Strategic Documents', box_type: 'document', description: 'Business strategy, market analysis, and positioning materials.', order: 1 },
    { phase: 4, title: 'Business Materials', box_type: 'deck', description: 'Investor materials, financial projections, and deal-related documents.', order: 2 },
];

app.post('/api/investroom/boxes/ensure-defaults', requireCSO, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.status(404).json({ error: 'Workspace not found' });

        const existing = await pool.query(
            `SELECT DISTINCT phase_number FROM investroom_phase_boxes WHERE workspace_id = $1`,
            [wsId]
        );
        const existingPhases = new Set(existing.rows.map(r => r.phase_number));

        let created = 0;
        for (const def of IR_DEFAULT_BOXES) {
            if (existingPhases.has(def.phase)) continue;
            await pool.query(
                `INSERT INTO investroom_phase_boxes (workspace_id, phase_number, title, box_type, description, order_index, created_by)
                 VALUES ($1, $2, $3, $4, $5, $6, $7)`,
                [wsId, def.phase, def.title, def.box_type, def.description, def.order, 'system']
            );
            created++;
        }
        if (created > 0) console.log(`[IR-BOXES] Default boxes created: ${created} for workspace ${wsId}`);
        res.json({ ok: true, created });
    } catch (err) {
        console.error('[IR-BOXES] Ensure defaults error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// PUT /api/investroom/boxes/:id — Update a box (CSO only)
app.put('/api/investroom/boxes/:id', requireCSO, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.status(404).json({ error: 'Workspace not found' });
        const { title, box_type, description, figure_label, slot_type, layout_width } = req.body;
        if (!title && !box_type && description === undefined && figure_label === undefined && slot_type === undefined && layout_width === undefined) return res.status(400).json({ error: 'Nothing to update' });
        const validTypes = ['publication','sop','data','figure','deck','document'];
        if (box_type && !validTypes.includes(box_type)) return res.status(400).json({ error: 'Invalid box_type' });

        const hasMirror = await checkIrMirrorCols();
        const sets = [];
        const vals = [req.params.id, wsId];
        let idx = 3;
        if (title) { sets.push(`title = $${idx++}`); vals.push(title.trim()); }
        if (box_type) { sets.push(`box_type = $${idx++}`); vals.push(box_type); }
        if (description !== undefined) { sets.push(`description = $${idx++}`); vals.push((description || '').trim() || null); }
        if (hasMirror && figure_label !== undefined) { sets.push(`figure_label = $${idx++}`); vals.push((figure_label || '').trim() || null); }
        if (hasMirror && slot_type !== undefined) { sets.push(`slot_type = $${idx++}`); vals.push(slot_type === 'data' || slot_type === 'sop' ? slot_type : null); }
        if (hasMirror && layout_width !== undefined) { sets.push(`layout_width = $${idx++}`); vals.push(layout_width === 'half' ? 'half' : 'full'); }
        sets.push('updated_at = NOW()');

        const result = await pool.query(
            `UPDATE investroom_phase_boxes SET ${sets.join(', ')} WHERE id = $1 AND workspace_id = $2 RETURNING *`,
            vals
        );
        if (result.rows.length === 0) return res.status(404).json({ error: 'Box not found' });
        res.json({ box: result.rows[0] });
    } catch (err) {
        console.error('[IR-BOXES] Update error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// DELETE /api/investroom/boxes/:id — Delete a box and its files from R2 (CSO only)
app.delete('/api/investroom/boxes/:id', requireCSO, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.status(404).json({ error: 'Workspace not found' });

        // Get files to clean up R2
        const files = await pool.query(
            `SELECT f.r2_object_key FROM investroom_phase_box_files f
             JOIN investroom_phase_boxes b ON b.id = f.box_id
             WHERE b.id = $1 AND b.workspace_id = $2`,
            [req.params.id, wsId]
        );
        // Delete box (CASCADE deletes files rows)
        const del = await pool.query(
            `DELETE FROM investroom_phase_boxes WHERE id = $1 AND workspace_id = $2 RETURNING id`,
            [req.params.id, wsId]
        );
        if (del.rows.length === 0) return res.status(404).json({ error: 'Box not found' });

        // Clean up R2 objects in background
        for (const f of files.rows) {
            try { if (r2Enabled()) await deleteFromR2(f.r2_object_key); } catch (e) {
                console.error('[IR-BOXES] R2 cleanup error:', e.message);
            }
        }
        console.log(`[IR-BOXES] Box deleted: ${req.params.id} (${files.rows.length} files) by ${req.session.user.researcher_id}`);
        res.json({ ok: true });
    } catch (err) {
        console.error('[IR-BOXES] Delete error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// POST /api/investroom/boxes/:id/files — Upload file to a box (CSO only)
app.post('/api/investroom/boxes/:id/files', requireCSO, irBoxUpload.single('file'), async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });
        if (!req.file) return res.status(400).json({ error: 'No file provided' });
        if (!r2Enabled()) return res.status(503).json({ error: 'Storage not configured' });
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.status(404).json({ error: 'Workspace not found' });

        // Verify box exists and belongs to workspace
        const box = await pool.query(
            `SELECT id, phase_number FROM investroom_phase_boxes WHERE id = $1 AND workspace_id = $2`,
            [req.params.id, wsId]
        );
        if (box.rows.length === 0) return res.status(404).json({ error: 'Box not found' });

        const ts = new Date().toISOString().replace(/[:.]/g, '-');
        const safeName = req.file.originalname.replace(/[^a-zA-Z0-9._-]/g, '_');
        const r2Key = `theralia/investroom/phase${box.rows[0].phase_number}/${req.params.id}/${ts}_${safeName}`;

        await uploadToR2(req.file.buffer, r2Key, req.file.mimetype);

        const result = await pool.query(
            `INSERT INTO investroom_phase_box_files (box_id, file_name, r2_object_key, mime_type, file_size, created_by)
             VALUES ($1, $2, $3, $4, $5, $6) RETURNING *`,
            [req.params.id, req.file.originalname, r2Key, req.file.mimetype, req.file.size, req.session.user.researcher_id]
        );
        console.log(`[IR-BOXES] File uploaded: ${result.rows[0].id} to box ${req.params.id} by ${req.session.user.researcher_id}`);
        res.json({ file: result.rows[0] });
    } catch (err) {
        console.error('[IR-BOXES] File upload error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// GET /api/investroom/files/:fileId/download — Download a box file (any authenticated user with access)
app.get('/api/investroom/files/:fileId/download', requireAuth, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });
        const result = await pool.query(
            `SELECT f.file_name, f.r2_object_key, f.mime_type
             FROM investroom_phase_box_files f
             JOIN investroom_phase_boxes b ON b.id = f.box_id
             JOIN workspaces w ON w.id = b.workspace_id AND w.slug = 'theralia'
             WHERE f.id = $1`,
            [req.params.fileId]
        );
        if (result.rows.length === 0) return res.status(404).json({ error: 'File not found' });
        if (!r2Enabled()) return res.status(503).json({ error: 'Storage not configured' });
        const { file_name, r2_object_key, mime_type } = result.rows[0];
        const stream = await downloadFromR2(r2_object_key);
        res.setHeader('Content-Type', mime_type || 'application/octet-stream');
        res.setHeader('Content-Disposition', `inline; filename="${file_name}"`);
        stream.pipe(res);
    } catch (err) {
        console.error('[IR-BOXES] File download error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// DELETE /api/investroom/files/:fileId — Delete a file from a box (CSO only)
app.delete('/api/investroom/files/:fileId', requireCSO, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.status(404).json({ error: 'Workspace not found' });

        const result = await pool.query(
            `DELETE FROM investroom_phase_box_files f
             USING investroom_phase_boxes b
             WHERE f.box_id = b.id AND f.id = $1 AND b.workspace_id = $2
             RETURNING f.r2_object_key, f.file_name`,
            [req.params.fileId, wsId]
        );
        if (result.rows.length === 0) return res.status(404).json({ error: 'File not found' });

        try { if (r2Enabled()) await deleteFromR2(result.rows[0].r2_object_key); } catch (e) {
            console.error('[IR-BOXES] R2 cleanup error:', e.message);
        }
        console.log(`[IR-BOXES] File deleted: ${req.params.fileId} by ${req.session.user.researcher_id}`);
        res.json({ ok: true });
    } catch (err) {
        console.error('[IR-BOXES] File delete error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// PATCH /api/investroom/files/:fileId/review — Approve/Revise/Discard a file (COO Luiza + SOP only)
app.patch('/api/investroom/files/:fileId/review', requireAuth, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });

        // Enforce: must be COO + name must be "Luiza I. Hernandez"
        const wsSlug = req.query.workspace || req.headers['x-workspace-slug'] || 'theralia';
        const wu = await pool.query(
            `SELECT wu.workspace_position, r.name
             FROM workspace_users wu
             JOIN workspaces w ON w.id = wu.workspace_id
             JOIN researchers r ON r.researcher_id = wu.user_id
             WHERE wu.user_id = $1 AND w.slug = $2 AND wu.is_active = TRUE
             LIMIT 1`,
            [req.session.user.researcher_id, wsSlug]
        );
        const pos = (wu.rows[0]?.workspace_position || '').toLowerCase();
        const rawName = (wu.rows[0]?.name || '').trim().replace(/\s+/g, ' ').toLowerCase();
        if (pos !== 'coo' || rawName !== 'luiza i. hernandez') {
            return res.status(403).json({ error: 'Access denied. Only COO Luiza I. Hernandez may review SOP files.' });
        }

        // Enforce: file must belong to a SOP-type box
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.status(404).json({ error: 'Workspace not found' });
        const file = await pool.query(
            `SELECT f.id, f.review_status, b.box_type
             FROM investroom_phase_box_files f
             JOIN investroom_phase_boxes b ON b.id = f.box_id
             WHERE f.id = $1 AND b.workspace_id = $2`,
            [req.params.fileId, wsId]
        );
        if (file.rows.length === 0) return res.status(404).json({ error: 'File not found' });
        if (file.rows[0].box_type !== 'sop') {
            return res.status(403).json({ error: 'Review actions are only allowed for SOP files.' });
        }

        const { action, note } = req.body;
        const validActions = ['approved', 'revision_needed', 'discarded'];
        if (!validActions.includes(action)) return res.status(400).json({ error: 'Invalid action. Use: approved, revision_needed, discarded' });

        const result = await pool.query(
            `UPDATE investroom_phase_box_files
             SET review_status = $1, review_note = $2, reviewed_by = $3, reviewed_at = NOW()
             WHERE id = $4
             RETURNING id, review_status, reviewed_by, reviewed_at`,
            [action, (note || '').trim() || null, req.session.user.name || req.session.user.researcher_id, req.params.fileId]
        );
        console.log(`[IR-BOXES] File reviewed: ${req.params.fileId} action=${action} by ${req.session.user.researcher_id}`);
        res.json({ file: result.rows[0] });
    } catch (err) {
        console.error('[IR-BOXES] File review error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

// POST /api/investroom/boxes/:id/move — Reorder a box (CSO only)
app.post('/api/investroom/boxes/:id/move', requireCSO, async (req, res) => {
    try {
        if (!(await checkIrTables())) return res.status(503).json({ error: 'Migration not applied' });
        const wsId = await getTheraliaWsId();
        if (!wsId) return res.status(404).json({ error: 'Workspace not found' });
        const { direction } = req.body;
        if (direction !== 'up' && direction !== 'down') return res.status(400).json({ error: 'direction must be up or down' });

        // Get the box and its siblings
        const box = await pool.query(
            `SELECT id, phase_number, order_index FROM investroom_phase_boxes WHERE id = $1 AND workspace_id = $2`,
            [req.params.id, wsId]
        );
        if (box.rows.length === 0) return res.status(404).json({ error: 'Box not found' });
        const { phase_number, order_index } = box.rows[0];

        // Find the adjacent box to swap with
        const neighbor = await pool.query(
            `SELECT id, order_index FROM investroom_phase_boxes
             WHERE workspace_id = $1 AND phase_number = $2 AND order_index ${direction === 'up' ? '<' : '>'} $3
             ORDER BY order_index ${direction === 'up' ? 'DESC' : 'ASC'}
             LIMIT 1`,
            [wsId, phase_number, order_index]
        );
        if (neighbor.rows.length === 0) return res.json({ ok: true, moved: false });

        // Swap order_index values
        const nId = neighbor.rows[0].id;
        const nIdx = neighbor.rows[0].order_index;
        await pool.query(`UPDATE investroom_phase_boxes SET order_index = $1, updated_at = NOW() WHERE id = $2`, [nIdx, req.params.id]);
        await pool.query(`UPDATE investroom_phase_boxes SET order_index = $1, updated_at = NOW() WHERE id = $2`, [order_index, nId]);

        res.json({ ok: true, moved: true });
    } catch (err) {
        console.error('[IR-BOXES] Move error:', err.message);
        res.status(500).json({ error: 'Server error' });
    }
});

