// END INVESTROOM PHASE UPLOADS
// =====================================================

// =====================================================
// ZOE — PI scientific & lab operations copilot
// -----------------------------------------------------
// Architecture:
//   PI portal browser -> Railway portal backend -> OpenClaw on Hostinger VPS
// The browser must never talk to OpenClaw directly. OpenClaw URL and gateway
// token live only here as env vars and are never exposed to the frontend.
// Telegram webhook reuses the same internal helper (zoeHandleChat) so all
// upstream calls funnel through this backend.
//
// OpenClaw deployment notes (Hostinger VPS):
//   - OpenClaw API service listens on 127.0.0.1:18791 (protected, token auth)
//   - OpenClaw Control UI listens on 127.0.0.1:18789 — DO NOT target the UI port
//   - Public reach goes through the VPS Nginx; OPENCLAW_BASE_URL must point to
//     the API service (port 18791), e.g. http://187.127.69.147:18791
//   - Chat route: /v1/chat/completions
//   - gateway.auth.mode = token; the token env on OpenClaw is OPENCLAW_GATEWAY_TOKEN.
//     On the Railway side we pass that same token via OPENCLAW_API_KEY in the
//     Authorization: Bearer <token> header.
//
// Required Railway env:
//   OPENCLAW_BASE_URL           e.g. http://187.127.69.147:18791  (API service, NOT UI)
//   OPENCLAW_CHAT_PATH          default /v1/chat/completions
//   OPENCLAW_API_KEY            OpenClaw gateway token (never logged, never sent to browser)
//   OPENCLAW_AUTH_HEADER        optional header name override, default "Authorization"
//   OPENCLAW_TIMEOUT_MS         optional, default 30000
//   TELEGRAM_BOT_TOKEN          telegram bot token
//   TELEGRAM_ALLOWED_USER_ID    comma-separated Telegram user ids allowed to talk to Zoe
//   TELEGRAM_WEBHOOK_SECRET     optional, checked against ?secret= query param
// =====================================================

const ZOE_SYSTEM_READ = "You are Zoe, the personal scientific and lab operations assistant to a PI in molecular medicine. In Read mode, you are analytical, careful, evidence based, thoughtful, and honest about uncertainty. You analyze files, discuss experiments, review data, answer questions about researchers and lab activity, and provide useful scientific feedback without taking actions.";
const ZOE_SYSTEM_WORK = "You are Zoe, the personal scientific and lab operations copilot to a PI in molecular medicine. In Work mode, you are proactive, organized, thoughtful, and operationally helpful. You can suggest actions, prepare structured follow up, draft supervision notes, draft feedback, recommend next steps, and support lab workflows within the PI permissions. You must remain transparent, grounded, and never claim actions were executed unless confirmed by the system.";

// In-memory store for Zoe session-uploaded files (ephemeral; not persisted to DB).
// TODO: swap to R2 + DB once deep content extraction is implemented.
const zoeFileStore = new Map();

// Lightweight extraction — PDF via pdf-parse, XLSX/CSV via xlsx. Images/unknown → null.
// Trims aggressively so we never blow past a reasonable upstream payload size.
// ---------------------------------------------------------------------------
// Zoe document extraction (Phase 3): buffer-based extractor used by
// /api/zoe/document/:id. Reuses pdf-parse and xlsx (already in the project).
// Gracefully returns { text, extraction_method, content_truncated, notes? }.
// Never throws; returns { text: null, error } on unsupported/failed input.
// ---------------------------------------------------------------------------
const ZOE_DOC_MAX_CHARS = 18000;
async function zoeExtractFromBuffer(buffer, contentType, filename) {
    const ext = (filename || '').toLowerCase().split('.').pop();
    const mime = (contentType || '').toLowerCase();
    const clip = (s) => {
        const t = String(s || '');
        return { text: t.slice(0, ZOE_DOC_MAX_CHARS), truncated: t.length > ZOE_DOC_MAX_CHARS };
    };
    try {
        // PDF
        if (mime.includes('pdf') || ext === 'pdf') {
            const pdfParse = require('pdf-parse');
            const parsed = await pdfParse(buffer);
            const raw = (parsed.text || '').replace(/\s+\n/g, '\n').trim();
            const { text, truncated } = clip(raw);
            return { text, extraction_method: 'pdf-parse', content_truncated: truncated, pages: parsed.numpages || null };
        }
        // Plain text / markdown / JSON
        if (mime.startsWith('text/') || ['txt', 'md', 'markdown', 'json', 'log'].includes(ext)) {
            const raw = buffer.toString('utf8');
            if (ext === 'json' || mime.includes('json')) {
                try {
                    const pretty = JSON.stringify(JSON.parse(raw), null, 2);
                    const { text, truncated } = clip(pretty);
                    return { text, extraction_method: 'json-pretty', content_truncated: truncated };
                } catch (_) { /* fall through to raw text */ }
            }
            const { text, truncated } = clip(raw);
            return { text, extraction_method: 'utf8-text', content_truncated: truncated };
        }
        // CSV / XLS / XLSX — compact preview only (first N rows per sheet)
        if (mime.includes('csv') || ext === 'csv' ||
            mime.includes('spreadsheetml') || mime.includes('ms-excel') ||
            ext === 'xlsx' || ext === 'xls') {
            const XLSX = require('xlsx');
            const wb = XLSX.read(buffer, { type: 'buffer' });
            const chunks = [];
            for (const name of wb.SheetNames) {
                const sheet = wb.Sheets[name];
                const rows = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: null });
                const preview = rows.slice(0, 40); // first 40 rows per sheet
                const totalRows = rows.length;
                chunks.push(`# Sheet: ${name} (${totalRows} row(s), showing first ${preview.length})\n`
                    + preview.map(r => (r || []).join(',')).join('\n'));
                if (chunks.join('\n\n').length > ZOE_DOC_MAX_CHARS) break;
            }
            const { text, truncated } = clip(chunks.join('\n\n'));
            return { text, extraction_method: 'xlsx-preview', content_truncated: truncated, sheets: wb.SheetNames };
        }
        // Unsupported binary formats
        return { text: null, error: `Unsupported content type for extraction: ${mime || ext || 'unknown'}` };
    } catch (err) {
        return { text: null, error: String(err && err.message || err) };
    }
}

async function zoeExtractFileText(file) {
    const ZOE_EXTRACT_MAX_CHARS = 12000;
    try {
        if (file.mimetype === 'application/pdf') {
            const pdfParse = require('pdf-parse');
            const parsed = await pdfParse(file.buffer);
            const text = (parsed.text || '').replace(/\s+\n/g, '\n').trim();
            return { text: text.slice(0, ZOE_EXTRACT_MAX_CHARS), pages: parsed.numpages || null, truncated: text.length > ZOE_EXTRACT_MAX_CHARS };
        }
        if (file.mimetype === 'text/csv' ||
            file.mimetype === 'application/vnd.ms-excel' ||
            file.mimetype === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet') {
            const XLSX = require('xlsx');
            const wb = XLSX.read(file.buffer, { type: 'buffer' });
            const chunks = [];
            for (const name of wb.SheetNames) {
                const csv = XLSX.utils.sheet_to_csv(wb.Sheets[name]);
                chunks.push(`# Sheet: ${name}\n${csv}`);
                if (chunks.join('\n\n').length > ZOE_EXTRACT_MAX_CHARS) break;
            }
            const text = chunks.join('\n\n');
            return { text: text.slice(0, ZOE_EXTRACT_MAX_CHARS), sheets: wb.SheetNames, truncated: text.length > ZOE_EXTRACT_MAX_CHARS };
        }
    } catch (err) {
        console.error('[ZOE] extract error for', file.originalname, err.message);
        return { text: null, error: err.message };
    }
    return null;
}

// Build an OpenAI-compatible /v1/chat/completions body from our internal Zoe payload.
function zoeBuildChatCompletionsBody(payload) {
    const model = process.env.OPENCLAW_MODEL || 'default';
    const messages = [];
    if (payload.system) messages.push({ role: 'system', content: String(payload.system) });
    // Attach portal context as a second system message so OpenClaw has grounding.
    const ctxBits = [];
    if (payload.mode) ctxBits.push('Mode: ' + payload.mode);
    if (payload.workspace) ctxBits.push('Workspace: ' + payload.workspace);
    if (payload.selected_file) ctxBits.push('Selected file: ' + JSON.stringify(payload.selected_file).slice(0, 2000));
    if (payload.glp_context) ctxBits.push('GLP Vision context: ' + JSON.stringify(payload.glp_context).slice(0, 1000));
    if (payload.portal_summary) ctxBits.push('Portal summary: ' + JSON.stringify(payload.portal_summary).slice(0, 1000));
    if (ctxBits.length) messages.push({ role: 'system', content: ctxBits.join('\n') });
    // Single cap across the whole pipeline. Large enough to carry instruction
    // (~2k) + LIVE PORTAL CONTEXT JSON (~6k) + RESOLVED DOCUMENT with
    // text_content up to ZOE_DOC_MAX_CHARS (~18k) + USER QUESTION, with
    // comfortable headroom. Raise further if you enlarge ZOE_DOC_MAX_CHARS.
    const ZOE_USER_MSG_CAP = 120000;
    const userContent = String(payload.message || '');
    const clipped = userContent.slice(0, ZOE_USER_MSG_CAP);
    if (userContent.length > ZOE_USER_MSG_CAP) {
        console.warn('[ZOE/diag] user message clipped at ' + ZOE_USER_MSG_CAP + ' (input=' + userContent.length + ')');
    }
    messages.push({ role: 'user', content: clipped });
    const body = { model, messages };
    if (process.env.OPENCLAW_MAX_TOKENS) body.max_tokens = parseInt(process.env.OPENCLAW_MAX_TOKENS, 10);
    if (process.env.OPENCLAW_TEMPERATURE) body.temperature = parseFloat(process.env.OPENCLAW_TEMPERATURE);
    return body;
}

async function callOpenClaw(payload) {
    const baseUrl = process.env.OPENCLAW_BASE_URL;
    const timeoutMs = parseInt(process.env.OPENCLAW_TIMEOUT_MS || '60000', 10);
    if (!baseUrl) {
        // Safe placeholder if OpenClaw is not yet wired — echo a graceful reply.
        return { reply: "[Zoe offline] OPENCLAW_BASE_URL is not configured. Your message was received: " + (payload.message || '').slice(0, 400) };
    }
    const headers = { 'Content-Type': 'application/json' };
    if (process.env.OPENCLAW_API_KEY) {
        const authHeader = process.env.OPENCLAW_AUTH_HEADER || 'Authorization';
        const val = authHeader.toLowerCase() === 'authorization'
            ? 'Bearer ' + process.env.OPENCLAW_API_KEY
            : process.env.OPENCLAW_API_KEY;
        headers[authHeader] = val;
    }
    // Path is configurable. OpenClaw (Hostinger VPS) exposes OpenAI-compatible
    // /v1/chat/completions behind the nginx-token gateway.
    let chatPath = process.env.OPENCLAW_CHAT_PATH || '/v1/chat/completions';
    if (!chatPath.startsWith('/')) chatPath = '/' + chatPath;
    const url = baseUrl.replace(/\/$/, '') + chatPath;
    const body = zoeBuildChatCompletionsBody(payload);

    console.log('[ZOE] -> POST ' + url + ' model=' + body.model + ' msgs=' + body.messages.length);
    // Promise.race timeout — no AbortController (avoids node-fetch abort quirks
    // that surfaced as "The user aborted a request" on long OpenClaw responses).
    const fetchPromise = fetch(url, { method: 'POST', headers, body: JSON.stringify(body) });
    const timeoutPromise = new Promise((_, reject) =>
        setTimeout(() => reject(new Error('TIMEOUT_' + timeoutMs + 'ms')), timeoutMs)
    );
    try {
        const r = await Promise.race([fetchPromise, timeoutPromise]);
        const text = await r.text();
        const ctype = r.headers.get('content-type') || '';
        console.log('[ZOE] <- status=' + r.status + ' content-type=' + ctype + ' body[0..200]=' + (text || '').slice(0, 200).replace(/\s+/g, ' '));
        let data = {};
        try { data = JSON.parse(text); } catch (_) { data = { reply: text }; }
        if (!r.ok) {
            const snippet = (text || '').slice(0, 200);
            return { reply: "[Zoe upstream error] HTTP " + r.status + " " + r.statusText + (snippet ? " — " + snippet : '') };
        }
        const content = (data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content)
            || data.reply || data.text || data.message;
        return { reply: content || '(no content)' };
    } catch (err) {
        if (err && typeof err.message === 'string' && err.message.startsWith('TIMEOUT_')) {
            return { reply: "[Zoe timeout] Upstream did not respond within " + timeoutMs + "ms." };
        }
        return { reply: "[Zoe connectivity error] " + (err && err.message ? err.message : String(err)) };
    }
}

// Build scoped summary context (PI + workspace scoping preserved).
async function zoeBuildContextSummary(userId, workspaceId) {
    const out = { pendingGlp: 0, revisionNeeded: 0, recentUploads: 0, activeProjects: 0, recentResearchers: [], experimentsNote: null };
    try {
        const pending = await pool.query(
            `SELECT COUNT(*)::int AS c FROM di_submissions WHERE status IN ('PENDING','SUBMITTED') AND (workspace_id = $1 OR workspace_id IS NULL)`,
            [workspaceId || DEFAULT_WORKSPACE_ID]
        ).catch(() => ({ rows: [{ c: 0 }] }));
        out.pendingGlp = pending.rows[0]?.c || 0;
    } catch (_) {}
    try {
        const rev = await pool.query(
            `SELECT COUNT(*)::int AS c FROM di_submissions WHERE status = 'REVISION_NEEDED' AND (workspace_id = $1 OR workspace_id IS NULL)`,
            [workspaceId || DEFAULT_WORKSPACE_ID]
        ).catch(() => ({ rows: [{ c: 0 }] }));
        out.revisionNeeded = rev.rows[0]?.c || 0;
    } catch (_) {}
    try {
        const recent = await pool.query(
            `SELECT COUNT(*)::int AS c FROM di_submissions WHERE created_at > NOW() - INTERVAL '7 days' AND (workspace_id = $1 OR workspace_id IS NULL)`,
            [workspaceId || DEFAULT_WORKSPACE_ID]
        ).catch(() => ({ rows: [{ c: 0 }] }));
        out.recentUploads = recent.rows[0]?.c || 0;
    } catch (_) {}
    try {
        const researchers = await pool.query(
            `SELECT DISTINCT uploader_researcher_id FROM di_submissions WHERE created_at > NOW() - INTERVAL '14 days' AND (workspace_id = $1 OR workspace_id IS NULL) LIMIT 8`,
            [workspaceId || DEFAULT_WORKSPACE_ID]
        ).catch(() => ({ rows: [] }));
        out.recentResearchers = researchers.rows.map(r => r.uploader_researcher_id).filter(Boolean);
    } catch (_) {}
    // TODO: wire active projects + experiments from di_studio_projects once finalized shape is stable.
    out.activeProjects = 0;
    out.experimentsNote = "Experiment summaries will be wired from Research Studio once the Phase 2 schema lands.";
    return out;
}

// Internal helper reused by /api/zoe/chat and Telegram webhook.
async function zoeHandleChat({ userId, workspaceId, message, mode, selectedFileId, glpContext }) {
    const system = mode === 'work' ? ZOE_SYSTEM_WORK : ZOE_SYSTEM_READ;
    const summary = await zoeBuildContextSummary(userId, workspaceId);
    let fileContext = null;
    if (selectedFileId && zoeFileStore.has(selectedFileId)) {
        const f = zoeFileStore.get(selectedFileId);
        fileContext = {
            fileName: f.name, mime: f.mime, size: f.size, summary: f.summary,
            extractedText: f.extractedText || null,
        };
    }
    // NOTE: do not pre-truncate here — the composed message from the Zoe tab
    // carries the full LIVE PORTAL CONTEXT + RESOLVED DOCUMENT + USER QUESTION
    // block. A single cap is applied in zoeBuildChatCompletionsBody().
    const composedMessage = String(message || '');
    // --- Temporary diagnostic log (metadata only; no content) -----------
    try {
        console.log('[ZOE/diag] msg_len=' + composedMessage.length
            + ' has_context=' + /LIVE PORTAL CONTEXT:/.test(composedMessage)
            + ' has_resolved_doc=' + /RESOLVED DOCUMENT:/.test(composedMessage)
            + ' has_selected_doc=' + /SELECTED DOCUMENT:/.test(composedMessage)
            + ' has_candidates=' + /CANDIDATE DOCUMENTS/.test(composedMessage)
            + ' has_user_question=' + /USER QUESTION:/.test(composedMessage));
    } catch (_) {}
    const payload = {
        system,
        mode: mode === 'work' ? 'work' : 'read',
        message: composedMessage,
        workspace: workspaceId || DEFAULT_WORKSPACE_SLUG,
        user_id: userId || null,
        selected_file: fileContext,
        glp_context: glpContext || null,
        portal_summary: summary,
    };
    return await callOpenClaw(payload);
}

// 1) POST /api/zoe/chat
app.post('/api/zoe/chat', requirePI, async (req, res) => {
    try {
        const { message, mode, selectedFileId, glpContext } = req.body || {};
        if (!message || typeof message !== 'string') return res.status(400).json({ error: 'message required' });
        const out = await zoeHandleChat({
            userId: req.session.user.id,
            workspaceId: req.session.user.workspace_id || DEFAULT_WORKSPACE_ID,
            message, mode, selectedFileId, glpContext,
        });
        // TODO: audit log Work-mode interactions once the audit table is available.
        res.json({ reply: out.reply });
    } catch (err) {
        console.error('[ZOE] chat error:', err.message);
        res.status(500).json({ error: 'Zoe chat failed' });
    }
});

// 2) GET /api/zoe/context-summary
app.get('/api/zoe/context-summary', requirePIRead, async (req, res) => {
    try {
        const s = await zoeBuildContextSummary(req.session.user.id, req.session.user.workspace_id);
        res.json(s);
    } catch (err) {
        console.error('[ZOE] context-summary error:', err.message);
        res.status(500).json({ error: 'Failed to load context summary' });
    }
});

// 2b) GET /api/zoe/context
// Richer structured live-portal snapshot for Zoe chat prompt injection.
// Read-only; PI + AI_bot; workspace-scoped. Compact by design — counts,
// top-N recents, light researcher overview, derived alerts, projects
// overview, focus recommendations, trends. Never dumps full datasets.
//
// Project linkage: uses di_submissions.rd_project_id → rd_projects when
// that column/table pair is available. NAT-Lab scientific projects come
// from di_studio_projects (no submission FK today); that listing is
// marked `derived: true` so the model knows counts may be partial.
app.get('/api/zoe/context', requirePIRead, async (req, res) => {
    const wsId = req.session.user.workspace_id || DEFAULT_WORKSPACE_ID;
    const userId = req.session.user.id || req.session.user.researcher_id || null;
    const affiliation = req.session.user.affiliation || null;
    const safeQ = async (sql, params, fallback) => {
        try { const r = await pool.query(sql, params); return r.rows; }
        catch (_) { return fallback; }
    };
    try {
        const base = await zoeBuildContextSummary(userId, wsId).catch(() => ({}));

        // Detect project-linkage capability once.
        let hasProjCol = false, hasRd = false;
        try { hasProjCol = await hasRdProjectIdCol(); } catch (_) { hasProjCol = false; }
        try { hasRd = await checkRdTables(); } catch (_) { hasRd = false; }
        const projectJoinable = hasProjCol && hasRd;

        // -- Counts -------------------------------------------------------
        const approvedRows = await safeQ(
            `SELECT COUNT(*)::int AS c FROM di_submissions
             WHERE status = 'APPROVED' AND (workspace_id = $1 OR workspace_id IS NULL)`,
            [wsId], [{ c: 0 }]
        );
        const pending_glp_count = Number(base.pendingGlp || 0);
        const revision_needed_count = Number(base.revisionNeeded || 0);
        const approved_count = approvedRows[0]?.c || 0;
        const recent_uploads_count = Number(base.recentUploads || 0);
        const active_projects_count = Number(base.activeProjects || 0);

        // -- Recent files (top 8, with optional project linkage) ---------
        const recentFilesSql = projectJoinable
            ? `SELECT s.submission_id, s.original_filename, s.file_type, s.status,
                      s.uploader_researcher_id, s.created_at, s.signed_at,
                      s.rd_project_id AS project_id, rp.title AS project_name,
                      a.affiliation AS uploader_affiliation,
                      (s.status = 'REVISION_NEEDED') AS is_recent_revision_needed
               FROM di_submissions s
               LEFT JOIN rd_projects rp ON rp.id = s.rd_project_id
               LEFT JOIN di_allowlist a ON a.researcher_id = s.uploader_researcher_id
               WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
               ORDER BY s.created_at DESC NULLS LAST
               LIMIT 8`
            : `SELECT s.submission_id, s.original_filename, s.file_type, s.status,
                      s.uploader_researcher_id, s.created_at, s.signed_at,
                      NULL::int AS project_id, NULL::text AS project_name,
                      a.affiliation AS uploader_affiliation,
                      (s.status = 'REVISION_NEEDED') AS is_recent_revision_needed
               FROM di_submissions s
               LEFT JOIN di_allowlist a ON a.researcher_id = s.uploader_researcher_id
               WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
               ORDER BY s.created_at DESC NULLS LAST
               LIMIT 8`;
        const recentFilesRows = await safeQ(recentFilesSql, [wsId], []);
        const recent_files = recentFilesRows.map(r => ({
            id: r.submission_id,
            title: r.original_filename,
            type: r.file_type,            // category proxy (kept name `type` for back-compat)
            category: r.file_type,
            uploader: r.uploader_researcher_id,
            affiliation: r.uploader_affiliation || null,
            status: r.status,
            date: r.created_at,
            signed_at: r.signed_at,
            project_id: r.project_id,
            project_name: r.project_name,
            is_recent_revision_needed: !!r.is_recent_revision_needed
        }));

        // -- Recent activity (top 10, last 30d) ---------------------------
        const recentActivitySql = projectJoinable
            ? `SELECT s.submission_id AS id, s.original_filename AS title, s.status,
                      s.uploader_researcher_id AS actor,
                      s.rd_project_id AS project_id, rp.title AS project_name,
                      COALESCE(s.signed_at, s.created_at) AS at
               FROM di_submissions s
               LEFT JOIN rd_projects rp ON rp.id = s.rd_project_id
               WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
                 AND COALESCE(s.signed_at, s.created_at) > NOW() - INTERVAL '30 days'
               ORDER BY COALESCE(s.signed_at, s.created_at) DESC NULLS LAST
               LIMIT 10`
            : `SELECT s.submission_id AS id, s.original_filename AS title, s.status,
                      s.uploader_researcher_id AS actor,
                      NULL::int AS project_id, NULL::text AS project_name,
                      COALESCE(s.signed_at, s.created_at) AS at
               FROM di_submissions s
               WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
                 AND COALESCE(s.signed_at, s.created_at) > NOW() - INTERVAL '30 days'
               ORDER BY COALESCE(s.signed_at, s.created_at) DESC NULLS LAST
               LIMIT 10`;
        const activityRows = await safeQ(recentActivitySql, [wsId], []);
        const recent_activity = activityRows.map(r => ({
            kind: 'submission',
            id: r.id,
            title: r.title,
            status: r.status,
            actor: r.actor,
            project_id: r.project_id,
            project_name: r.project_name,
            at: r.at
        }));

        // -- Researcher overview (top 10 active, enriched) ---------------
        const researcherRows = await safeQ(
            `SELECT s.uploader_researcher_id AS rid,
                    a.name AS name,
                    COUNT(*)::int AS recent_uploads,
                    SUM(CASE WHEN s.status IN ('PENDING','SUBMITTED') THEN 1 ELSE 0 END)::int AS pending,
                    SUM(CASE WHEN s.status = 'REVISION_NEEDED' THEN 1 ELSE 0 END)::int AS revision_needed,
                    SUM(CASE WHEN s.status = 'APPROVED' THEN 1 ELSE 0 END)::int AS approved,
                    MAX(s.created_at) AS last_upload_at
             FROM di_submissions s
             LEFT JOIN di_allowlist a ON a.researcher_id = s.uploader_researcher_id
             WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
               AND s.created_at > NOW() - INTERVAL '30 days'
               AND s.uploader_researcher_id IS NOT NULL
             GROUP BY s.uploader_researcher_id, a.name
             ORDER BY recent_uploads DESC
             LIMIT 10`,
            [wsId], []
        );
        const researcher_overview = researcherRows.map(r => ({
            researcher_id: r.rid,
            name: r.name || null,
            recent_uploads: r.recent_uploads,
            pending: r.pending,
            revision_needed: r.revision_needed,
            approved: r.approved,
            last_upload_at: r.last_upload_at
        }));

        // -- Projects overview --------------------------------------------
        // Primary path: aggregate submissions by rd_project_id. Secondary
        // path: list di_studio_projects (NAT-Lab scientific) as derived.
        let projects_overview = [];
        let projects_derived = false;
        if (projectJoinable) {
            const projRows = await safeQ(
                `SELECT rp.id AS project_id, rp.title AS project_name, rp.status,
                        COUNT(s.*)::int AS recent_files_count,
                        SUM(CASE WHEN s.status IN ('PENDING','SUBMITTED') THEN 1 ELSE 0 END)::int AS pending_count,
                        SUM(CASE WHEN s.status = 'REVISION_NEEDED' THEN 1 ELSE 0 END)::int AS revision_needed_count,
                        MAX(s.created_at) AS last_activity_at
                 FROM rd_projects rp
                 LEFT JOIN di_submissions s
                   ON s.rd_project_id = rp.id
                   AND (s.workspace_id = $1 OR s.workspace_id IS NULL)
                   AND s.created_at > NOW() - INTERVAL '60 days'
                 WHERE rp.workspace_id = $1
                 GROUP BY rp.id, rp.title, rp.status
                 ORDER BY last_activity_at DESC NULLS LAST, rp.updated_at DESC NULLS LAST
                 LIMIT 8`,
                [wsId], []
            );
            projects_overview = projRows.map(r => {
                const stale = !r.last_activity_at ||
                    (Date.now() - new Date(r.last_activity_at).getTime()) > 21 * 24 * 3600 * 1000;
                let health = 'good';
                if ((r.revision_needed_count || 0) > 0) health = 'attention';
                else if ((r.pending_count || 0) >= 3 || stale) health = 'watch';
                return {
                    project_id: r.project_id,
                    project_name: r.project_name,
                    status: r.status,
                    recent_files_count: r.recent_files_count || 0,
                    pending_count: r.pending_count || 0,
                    revision_needed_count: r.revision_needed_count || 0,
                    last_activity_at: r.last_activity_at,
                    stale,
                    health
                };
            });
        }
        if (projects_overview.length === 0 && affiliation) {
            // Fallback: NAT-Lab scientific projects (no submission FK exists)
            const studioRows = await safeQ(
                `SELECT p.id AS project_id, p.title AS project_name, p.status,
                        p.updated_at AS last_activity_at
                 FROM di_studio_projects p
                 WHERE p.affiliation = $1
                 ORDER BY p.updated_at DESC NULLS LAST
                 LIMIT 8`,
                [affiliation], []
            );
            projects_overview = studioRows.map(r => {
                const stale = !r.last_activity_at ||
                    (Date.now() - new Date(r.last_activity_at).getTime()) > 30 * 24 * 3600 * 1000;
                return {
                    project_id: r.project_id,
                    project_name: r.project_name,
                    status: r.status,
                    recent_files_count: null,
                    pending_count: null,
                    revision_needed_count: null,
                    last_activity_at: r.last_activity_at,
                    stale,
                    health: stale ? 'watch' : 'good'
                };
            });
            projects_derived = studioRows.length > 0;
        }

        // -- Alerts (enriched) --------------------------------------------
        const alerts = [];
        if (pending_glp_count > 0) alerts.push({
            level: pending_glp_count >= 5 ? 'warn' : 'info',
            code: 'pending_approvals_exist',
            message: `${pending_glp_count} submission(s) pending PI approval.`
        });
        if (revision_needed_count > 0) alerts.push({
            level: 'warn', code: 'revision_needed_exists',
            message: `${revision_needed_count} submission(s) need revision.`
        });
        if (recent_uploads_count === 0) alerts.push({
            level: 'info', code: 'no_recent_uploads',
            message: 'No uploads in the last 7 days.'
        });
        // Researcher-level: anyone with >=3 pending items
        for (const r of researcher_overview) {
            if ((r.pending || 0) >= 3) {
                alerts.push({
                    level: 'warn', code: 'researcher_many_pending',
                    message: `${r.name || r.researcher_id} has ${r.pending} pending item(s).`,
                    entity_type: 'researcher', entity_id: r.researcher_id
                });
            }
        }
        // Recent upload spike: >10 in last 7d
        if (recent_uploads_count >= 10) alerts.push({
            level: 'info', code: 'recent_upload_spike',
            message: `${recent_uploads_count} uploads in the last 7 days.`
        });
        // Project-level
        for (const p of projects_overview) {
            if ((p.revision_needed_count || 0) > 0) alerts.push({
                level: 'warn', code: 'project_revision_needed',
                message: `Project "${p.project_name}" has ${p.revision_needed_count} revision-needed item(s).`,
                entity_type: 'project', entity_id: p.project_id
            });
            if (p.stale && (p.pending_count || 0) === 0) alerts.push({
                level: 'info', code: 'project_stale',
                message: `Project "${p.project_name}" has no recent activity.`,
                entity_type: 'project', entity_id: p.project_id
            });
        }
        if (projects_overview.length === 0) alerts.push({
            level: 'info', code: 'no_active_projects_linked',
            message: 'No active projects linked to this workspace context.'
        });
        // Missing project association on recent files (only when linkage is real)
        if (projectJoinable) {
            const unlinked = recent_files.filter(f => !f.project_id).length;
            if (unlinked >= 3) alerts.push({
                level: 'info', code: 'recent_files_missing_project',
                message: `${unlinked} of ${recent_files.length} recent files have no project association.`
            });
        }

        // -- Focus recommendations (top 3-5) -----------------------------
        const focus_recommendations = [];
        // Rank projects by score (revision > pending > stale)
        const projScored = projects_overview.map(p => ({
            ref: p,
            score: (p.revision_needed_count || 0) * 3 + (p.pending_count || 0) * 2 + (p.stale ? 1 : 0)
        })).filter(x => x.score > 0).sort((a, b) => b.score - a.score);
        for (const x of projScored.slice(0, 3)) {
            const reasonParts = [];
            if (x.ref.pending_count) reasonParts.push(`${x.ref.pending_count} pending`);
            if (x.ref.revision_needed_count) reasonParts.push(`${x.ref.revision_needed_count} revision-needed`);
            if (x.ref.stale && reasonParts.length === 0) reasonParts.push('stale activity');
            focus_recommendations.push({
                type: 'project',
                label: x.ref.project_name,
                reason: reasonParts.join(' and ') + ' file(s)',
                priority: (x.ref.revision_needed_count || 0) > 0 ? 'high' : 'medium'
            });
        }
        // Rank researchers by pending + revision_needed
        const resScored = researcher_overview.map(r => ({
            ref: r,
            score: (r.pending || 0) * 2 + (r.revision_needed || 0) * 3
        })).filter(x => x.score > 0).sort((a, b) => b.score - a.score);
        for (const x of resScored.slice(0, 2)) {
            focus_recommendations.push({
                type: 'researcher',
                label: x.ref.name || x.ref.researcher_id,
                reason: `${x.ref.pending || 0} pending, ${x.ref.revision_needed || 0} revision-needed`,
                priority: (x.ref.revision_needed || 0) > 0 ? 'high' : 'medium'
            });
        }
        if (focus_recommendations.length === 0 && pending_glp_count > 0) {
            focus_recommendations.push({
                type: 'glp',
                label: 'Pending GLP queue',
                reason: `${pending_glp_count} submission(s) awaiting PI review`,
                priority: pending_glp_count >= 5 ? 'high' : 'medium'
            });
        }

        // -- Trends (last 7 days) ----------------------------------------
        const trendsRow = await safeQ(
            `SELECT
                SUM(CASE WHEN created_at > NOW() - INTERVAL '7 days' THEN 1 ELSE 0 END)::int AS uploads_last_7d,
                SUM(CASE WHEN status = 'APPROVED' AND COALESCE(signed_at, updated_at, created_at) > NOW() - INTERVAL '7 days' THEN 1 ELSE 0 END)::int AS approvals_last_7d,
                SUM(CASE WHEN status = 'REVISION_NEEDED' AND COALESCE(updated_at, created_at) > NOW() - INTERVAL '7 days' THEN 1 ELSE 0 END)::int AS revisions_last_7d
             FROM di_submissions
             WHERE (workspace_id = $1 OR workspace_id IS NULL)`,
            [wsId], [{ uploads_last_7d: null, approvals_last_7d: null, revisions_last_7d: null }]
        );
        const trends = {
            uploads_last_7d: trendsRow[0]?.uploads_last_7d ?? null,
            approvals_last_7d: trendsRow[0]?.approvals_last_7d ?? null,
            revisions_last_7d: trendsRow[0]?.revisions_last_7d ?? null
        };

        // -- Summary block (derived) -------------------------------------
        let priority_level = 'normal';
        const criticalCount = alerts.filter(a => a.level === 'warn').length;
        if (revision_needed_count > 0 || pending_glp_count >= 5 || criticalCount >= 3) priority_level = 'high';
        else if (pending_glp_count > 0 || criticalCount >= 1) priority_level = 'elevated';
        const headlineParts = [];
        if (pending_glp_count > 0) headlineParts.push(`${pending_glp_count} pending`);
        if (revision_needed_count > 0) headlineParts.push(`${revision_needed_count} revision-needed`);
        if (projects_overview.length > 0) headlineParts.push(`${projects_overview.length} project(s) tracked`);
        if (recent_uploads_count > 0) headlineParts.push(`${recent_uploads_count} upload(s) last 7d`);
        const headline = headlineParts.length
            ? headlineParts.join(', ') + '.'
            : 'Lab is quiet — no pending approvals or revisions.';
        const summary = {
            priority_level,
            headline,
            needs_attention: pending_glp_count > 0 || revision_needed_count > 0 || criticalCount > 0
        };

        // -- Draft projects (Zoe idea layer, top 8) ----------------------
        // Compact shape only — no joins. Silently empty if table missing.
        let draft_projects = [];
        if (await checkZoeDraftsTable()) {
            const draftRows = await safeQ(
                `SELECT id, title, status, created_at, tags
                 FROM zoe_project_drafts
                 WHERE (workspace_id = $1 OR workspace_id IS NULL)
                   AND status IN ('draft', 'under_review')
                 ORDER BY created_at DESC
                 LIMIT 8`,
                [wsId], []
            );
            draft_projects = draftRows.map(r => ({
                id: r.id,
                title: r.title,
                status: r.status,
                created_at: r.created_at,
                tags: r.tags || null
            }));
        }

        res.json({
            generated_at: new Date().toISOString(),
            workspace_id: wsId,
            summary,
            pending_glp_count,
            revision_needed_count,
            approved_count,
            recent_uploads_count,
            active_projects_count,
            trends,
            recent_files,
            recent_activity,
            researcher_overview,
            projects_overview,
            projects_derived,                 // true => counts are limited / derived from di_studio_projects
            focus_recommendations,
            alerts,
            draft_projects,
            // Neutral note only. Never leak internal roadmap wording here —
            // it gets echoed back through Zoe and confuses users.
            notes: null
        });
    } catch (err) {
        console.error('[ZOE] context error:', err.message);
        res.status(500).json({ error: 'Failed to build Zoe context' });
    }
});

// ---------------------------------------------------------------------------
// Zoe project drafts (idea layer) — migration 062
// ---------------------------------------------------------------------------
// Separate from live projects. PI can always create; AI_bot only with the
// `create_project_drafts` capability. Edits/deletes are PI-only in v1.
let zoeDraftsTableExists = null;
let zoeDraftsTableLastCheck = 0;
async function checkZoeDraftsTable() {
    const now = Date.now();
    if (zoeDraftsTableExists === null || zoeDraftsTableExists === false ||
        (now - zoeDraftsTableLastCheck > 60000)) {
        try {
            const r = await pool.query(
                `SELECT table_name FROM information_schema.tables WHERE table_name = 'zoe_project_drafts'`
            );
            zoeDraftsTableExists = r.rows.length > 0;
            zoeDraftsTableLastCheck = now;
        } catch (_) { zoeDraftsTableExists = false; }
    }
    return zoeDraftsTableExists;
}
const VALID_DRAFT_STATUSES = ['draft', 'under_review', 'approved', 'archived'];

// GET /api/zoe/project-drafts — list drafts for this workspace.
// PI + AI_bot (read visibility). Optional ?status=... filter.
app.get('/api/zoe/project-drafts', requirePIRead, async (req, res) => {
    try {
        if (!(await checkZoeDraftsTable())) {
            return res.json({ drafts: [], column_missing: true });
        }
        const wsId = req.session.user.workspace_id || DEFAULT_WORKSPACE_ID;
        const status = typeof req.query.status === 'string' && VALID_DRAFT_STATUSES.includes(req.query.status)
            ? req.query.status : null;
        const params = [wsId];
        let sql = `SELECT id, workspace_id, title, short_description, notes, status,
                          tags, related_project_id, created_by, created_by_role,
                          created_at, updated_at
                   FROM zoe_project_drafts
                   WHERE (workspace_id = $1 OR workspace_id IS NULL)`;
        if (status) { params.push(status); sql += ` AND status = $2`; }
        sql += ` ORDER BY created_at DESC LIMIT 100`;
        const r = await pool.query(sql, params);
        res.json({ drafts: r.rows });
    } catch (err) {
        console.error('[ZOE-DRAFTS] list error:', err.message);
        res.status(500).json({ error: 'Failed to list drafts' });
    }
});

// POST /api/zoe/project-drafts — create a new draft idea.
// PI always; AI_bot only with capability `create_project_drafts`.
app.post('/api/zoe/project-drafts', requirePIorCap('create_project_drafts'), async (req, res) => {
    try {
        if (!(await checkZoeDraftsTable())) {
            return res.status(400).json({ error: 'Drafts table not available (run migration 062)' });
        }
        const b = req.body && typeof req.body === 'object' ? req.body : {};
        const title = (b.title || '').toString().trim();
        if (!title) return res.status(400).json({ error: 'title required' });
        if (title.length > 255) return res.status(400).json({ error: 'title too long (max 255)' });
        const short_description = b.short_description ? String(b.short_description).slice(0, 2000) : null;
        const notes = b.notes ? String(b.notes).slice(0, 20000) : null;
        const statusIn = (b.status || 'draft').toString();
        const status = VALID_DRAFT_STATUSES.includes(statusIn) ? statusIn : 'draft';
        const tags = b.tags ? String(b.tags).slice(0, 500) : null;
        const related_project_id = Number.isInteger(b.related_project_id) ? b.related_project_id : null;
        const wsId = req.session.user.workspace_id || DEFAULT_WORKSPACE_ID;
        const createdBy = req.session.user.researcher_id || req.session.user.id || 'unknown';
        const createdByRole = req.session.user.role || null;
        const r = await pool.query(
            `INSERT INTO zoe_project_drafts
                (workspace_id, title, short_description, notes, status, tags,
                 related_project_id, created_by, created_by_role)
             VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)
             RETURNING *`,
            [wsId, title, short_description, notes, status, tags, related_project_id, createdBy, createdByRole]
        );
        console.log(`[ZOE-DRAFTS] created id=${r.rows[0].id} by=${createdBy} role=${createdByRole}`);
        res.json({ success: true, draft: r.rows[0] });
    } catch (err) {
        console.error('[ZOE-DRAFTS] create error:', err.message);
        res.status(500).json({ error: 'Failed to create draft' });
    }
});

// PATCH /api/zoe/project-drafts/:id — PI only in v1.
app.patch('/api/zoe/project-drafts/:id', requirePI, async (req, res) => {
    try {
        if (!(await checkZoeDraftsTable())) return res.status(400).json({ error: 'Drafts table not available' });
        const id = parseInt(req.params.id, 10);
        if (!Number.isInteger(id)) return res.status(400).json({ error: 'invalid id' });
        const b = req.body && typeof req.body === 'object' ? req.body : {};
        const fields = [];
        const vals = [];
        let i = 1;
        const push = (col, v) => { fields.push(`${col} = $${i++}`); vals.push(v); };
        if (typeof b.title === 'string') push('title', b.title.slice(0, 255));
        if (typeof b.short_description === 'string') push('short_description', b.short_description.slice(0, 2000));
        if (typeof b.notes === 'string') push('notes', b.notes.slice(0, 20000));
        if (typeof b.status === 'string' && VALID_DRAFT_STATUSES.includes(b.status)) push('status', b.status);
        if (typeof b.tags === 'string') push('tags', b.tags.slice(0, 500));
        if (b.related_project_id === null || Number.isInteger(b.related_project_id)) push('related_project_id', b.related_project_id);
        if (fields.length === 0) return res.status(400).json({ error: 'no updatable fields provided' });
        push('updated_at', new Date());
        vals.push(id);
        const r = await pool.query(
            `UPDATE zoe_project_drafts SET ${fields.join(', ')} WHERE id = $${i} RETURNING *`,
            vals
        );
        if (r.rows.length === 0) return res.status(404).json({ error: 'draft not found' });
        res.json({ success: true, draft: r.rows[0] });
    } catch (err) {
        console.error('[ZOE-DRAFTS] patch error:', err.message);
        res.status(500).json({ error: 'Failed to update draft' });
    }
});

// DELETE /api/zoe/project-drafts/:id — PI only in v1.
app.delete('/api/zoe/project-drafts/:id', requirePI, async (req, res) => {
    try {
        if (!(await checkZoeDraftsTable())) return res.status(400).json({ error: 'Drafts table not available' });
        const id = parseInt(req.params.id, 10);
        if (!Number.isInteger(id)) return res.status(400).json({ error: 'invalid id' });
        const r = await pool.query(`DELETE FROM zoe_project_drafts WHERE id = $1`, [id]);
        if (r.rowCount === 0) return res.status(404).json({ error: 'draft not found' });
        res.json({ success: true });
    } catch (err) {
        console.error('[ZOE-DRAFTS] delete error:', err.message);
        res.status(500).json({ error: 'Failed to delete draft' });
    }
});

// ---------------------------------------------------------------------------
// Zoe Document Intelligence (Phase 3): listing + retrieval with extraction.
// Read-only. PI + AI_bot via requirePIRead. Workspace-scoped. No writes.
// Sources: di_submissions (primary), di_group_documents (secondary).
// IDs are namespaced as `sub:<submission_id>` and `grp:<id>` so either
// source can be resolved through the same /api/zoe/document/:id route.
// ---------------------------------------------------------------------------
const ZOE_READABLE_EXTS = new Set(['pdf', 'txt', 'md', 'markdown', 'json', 'log', 'csv', 'xls', 'xlsx']);
function zoeDocCanReadContent(filename, fileType) {
    const ext = (filename || '').toLowerCase().split('.').pop();
    if (ZOE_READABLE_EXTS.has(ext)) return true;
    const t = (fileType || '').toLowerCase();
    return /pdf|text|csv|json|excel|spreadsheet|markdown/.test(t);
}

// GET /api/zoe/documents — compact list of recent portal docs Zoe can read.
app.get('/api/zoe/documents', requirePIRead, async (req, res) => {
    try {
        const wsId = req.session.user.workspace_id || DEFAULT_WORKSPACE_ID;
        const recent = req.query.recent === '0' ? false : true;
        const wantType = typeof req.query.type === 'string' ? req.query.type : null;
        const wantStatus = typeof req.query.status === 'string' ? req.query.status : null;
        const wantProject = req.query.project_id ? parseInt(req.query.project_id, 10) : null;

        // Column existence for project linkage
        let hasProjCol = false, hasRd = false;
        try { hasProjCol = await hasRdProjectIdCol(); } catch (_) {}
        try { hasRd = await checkRdTables(); } catch (_) {}
        const joinable = hasProjCol && hasRd;

        const subSql = joinable
            ? `SELECT s.submission_id AS id, s.original_filename AS title, s.file_type AS type,
                      s.status, s.uploader_researcher_id AS uploader, s.created_at AS date,
                      s.r2_object_key, s.rd_project_id AS project_id, rp.title AS project_name
               FROM di_submissions s
               LEFT JOIN rd_projects rp ON rp.id = s.rd_project_id
               WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
                 AND s.r2_object_key IS NOT NULL
                 AND s.status <> 'DISCARDED'
                 ${wantType ? ` AND s.file_type = $2` : ''}
                 ${wantStatus ? ` AND s.status = ${wantType ? '$3' : '$2'}` : ''}
                 ${wantProject ? ` AND s.rd_project_id = $${2 + (wantType?1:0) + (wantStatus?1:0)}` : ''}
               ORDER BY s.created_at DESC NULLS LAST
               LIMIT ${recent ? 20 : 60}`
            : `SELECT s.submission_id AS id, s.original_filename AS title, s.file_type AS type,
                      s.status, s.uploader_researcher_id AS uploader, s.created_at AS date,
                      s.r2_object_key, NULL::int AS project_id, NULL::text AS project_name
               FROM di_submissions s
               WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
                 AND s.r2_object_key IS NOT NULL
                 AND s.status <> 'DISCARDED'
                 ${wantType ? ` AND s.file_type = $2` : ''}
                 ${wantStatus ? ` AND s.status = ${wantType ? '$3' : '$2'}` : ''}
               ORDER BY s.created_at DESC NULLS LAST
               LIMIT ${recent ? 20 : 60}`;
        const subParams = [wsId];
        if (wantType) subParams.push(wantType);
        if (wantStatus) subParams.push(wantStatus);
        if (wantProject && joinable) subParams.push(wantProject);

        let subRows = [];
        try { subRows = (await pool.query(subSql, subParams)).rows; } catch (e) { console.error('[ZOE-DOCS] submissions query:', e.message); }

        const subItems = subRows.map(r => ({
            id: `sub:${r.id}`,
            title: r.title,
            type: r.type,
            category: r.type,
            uploader: r.uploader,
            date: r.date,
            status: r.status,
            project_id: r.project_id,
            project_name: r.project_name,
            source_kind: 'submission',
            can_read_content: zoeDocCanReadContent(r.title, r.type)
        }));

        // Group documents — intentionally global for v1.
        // TODO (follow-up): di_group_documents has no workspace_id column
        // (migrations 006 + 007). If/when multiple lab workspaces share this
        // portal, add `workspace_id` via a new migration and tighten this
        // query to `WHERE (workspace_id = $1 OR workspace_id IS NULL)` to
        // match the submission scoping pattern used above.
        let grpItems = [];
        try {
            const grpRows = (await pool.query(
                `SELECT id, title, category, filename, file_type, created_at, uploaded_by
                 FROM di_group_documents WHERE is_active = true
                 ORDER BY created_at DESC NULLS LAST LIMIT 20`
            )).rows;
            grpItems = grpRows.map(r => ({
                id: `grp:${r.id}`,
                title: r.title || r.filename,
                type: r.file_type,
                category: r.category,
                uploader: r.uploaded_by,
                date: r.created_at,
                status: 'ACTIVE',
                project_id: null,
                project_name: null,
                source_kind: 'group_document',
                can_read_content: zoeDocCanReadContent(r.filename, r.file_type)
            }));
        } catch (_) { /* table may be absent */ }

        const documents = [...subItems, ...grpItems]
            .sort((a, b) => new Date(b.date || 0) - new Date(a.date || 0))
            .slice(0, recent ? 25 : 80);

        res.json({ count: documents.length, documents });
    } catch (err) {
        console.error('[ZOE-DOCS] list error:', err.message);
        res.status(500).json({ error: 'Failed to list documents' });
    }
});

// GET /api/zoe/find-document?q=...
// Natural-language document resolver. Compact SQL search across
// di_submissions + di_group_documents. Returns top-5 matches with a
// lightweight score + match_reason. No embeddings, no indexing.
// Strategy: tokenize query, ILIKE against title/filename/category/uploader
// and (if available) project name; boost for type hints ("paper", "sop",
// "presentation", "report", "data"), boost for recency, penalize missing
// object keys. The frontend decides auto-read vs. disambiguate.
app.get('/api/zoe/find-document', requirePIRead, async (req, res) => {
    try {
        const wsId = req.session.user.workspace_id || DEFAULT_WORKSPACE_ID;
        const rawQ = String(req.query.q || '').trim();
        if (!rawQ) return res.json({ query: '', matches: [] });

        const qLower = rawQ.toLowerCase();
        // Token list (keep words ≥3 chars; keep numbers; drop stopwords)
        const STOP = new Set(['the','and','from','with','what','does','read','show','tell','find','summarize','analyze','give','please','about','that','this','these','paper','papers','file','files','sop','sops','report','reports','presentation','presentations','data','doc','docs','document','documents','latest','newest','last','recent']);
        const tokens = qLower.split(/[^a-z0-9]+/)
            .filter(t => t.length >= 2 && !STOP.has(t)).slice(0, 10);

        // Type hints shape the scoring
        const wantsPaper = /\b(paper|publication|article|journal|doi)\b/.test(qLower);
        const wantsSop = /\bsop\b/.test(qLower);
        const wantsPresentation = /\b(presentation|slides?|deck|ppt|pptx)\b/.test(qLower);
        const wantsReport = /\breport\b/.test(qLower);
        const wantsData = /\b(data|dataset|csv|xls|xlsx|results?)\b/.test(qLower);
        const wantsLatest = /\b(latest|newest|last|recent)\b/.test(qLower);

        // Column availability for project linkage
        let hasProjCol = false, hasRd = false;
        try { hasProjCol = await hasRdProjectIdCol(); } catch (_) {}
        try { hasRd = await checkRdTables(); } catch (_) {}
        const joinable = hasProjCol && hasRd;

        // Build ILIKE pattern list. If no tokens, fall back to whole query.
        const patterns = (tokens.length > 0 ? tokens : [qLower]).map(t => `%${t}%`);
        const patternParams = patterns.map((_, i) => `$${i + 2}`);
        const orClause = [
            `s.original_filename ILIKE ANY (ARRAY[${patternParams.join(',')}])`,
            `COALESCE(s.file_type, '') ILIKE ANY (ARRAY[${patternParams.join(',')}])`,
            `COALESCE(s.uploader_researcher_id, '') ILIKE ANY (ARRAY[${patternParams.join(',')}])`,
            joinable ? `COALESCE(rp.title, '') ILIKE ANY (ARRAY[${patternParams.join(',')}])` : null,
        ].filter(Boolean).join(' OR ');

        const subSql = joinable
            ? `SELECT s.submission_id AS id, s.original_filename AS title, s.file_type AS type,
                      s.status, s.uploader_researcher_id AS uploader, s.created_at AS date,
                      s.r2_object_key, s.rd_project_id AS project_id, rp.title AS project_name
               FROM di_submissions s
               LEFT JOIN rd_projects rp ON rp.id = s.rd_project_id
               WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
                 AND s.status <> 'DISCARDED'
                 AND (${orClause})
               ORDER BY s.created_at DESC NULLS LAST
               LIMIT 40`
            : `SELECT s.submission_id AS id, s.original_filename AS title, s.file_type AS type,
                      s.status, s.uploader_researcher_id AS uploader, s.created_at AS date,
                      s.r2_object_key, NULL::int AS project_id, NULL::text AS project_name
               FROM di_submissions s
               WHERE (s.workspace_id = $1 OR s.workspace_id IS NULL)
                 AND s.status <> 'DISCARDED'
                 AND (${orClause})
               ORDER BY s.created_at DESC NULLS LAST
               LIMIT 40`;
        const subParams = [wsId, ...patterns];

        let subRows = [];
        try { subRows = (await pool.query(subSql, subParams)).rows; }
        catch (e) { console.error('[ZOE-FIND] submissions query:', e.message); }

        // Group docs (no workspace column yet — see TODO at /api/zoe/documents)
        let grpRows = [];
        try {
            const grpSql = `SELECT id, title, category, filename, file_type, created_at, uploaded_by, r2_object_key
                            FROM di_group_documents
                            WHERE is_active = true
                              AND (
                                COALESCE(title, '') ILIKE ANY (ARRAY[${patternParams.map((_,i)=>'$'+(i+1)).join(',')}])
                                OR COALESCE(filename, '') ILIKE ANY (ARRAY[${patternParams.map((_,i)=>'$'+(i+1)).join(',')}])
                                OR COALESCE(category, '') ILIKE ANY (ARRAY[${patternParams.map((_,i)=>'$'+(i+1)).join(',')}])
                              )
                            ORDER BY created_at DESC NULLS LAST
                            LIMIT 40`;
            grpRows = (await pool.query(grpSql, patterns)).rows;
        } catch (_) {}

        const norm = (s) => String(s || '').toLowerCase();
        const now = Date.now();
        const score = (row, kind) => {
            const hay = [
                norm(row.title), norm(row.filename), norm(row.type),
                norm(row.category), norm(row.uploader), norm(row.project_name)
            ].join(' | ');
            let s = 0;
            const reasons = [];
            // Exact full-query substring = strong
            if (qLower.length >= 3 && hay.includes(qLower)) { s += 40; reasons.push('exact query match'); }
            // Each token that hits title/filename = 6; other fields = 3
            const titleHay = norm(row.title || row.filename);
            for (const t of tokens) {
                if (!t) continue;
                if (titleHay.includes(t)) { s += 6; reasons.push(`"${t}" in title`); }
                else if (hay.includes(t)) { s += 3; }
            }
            // Type hints
            const typeStr = norm((row.type || '') + ' ' + (row.category || '') + ' ' + (row.filename || row.title || ''));
            if (wantsPaper && /paper|publication|journal|article|\.pdf/.test(typeStr)) { s += 8; reasons.push('matches "paper" hint'); }
            if (wantsSop && /sop/.test(typeStr)) { s += 8; reasons.push('matches "SOP" hint'); }
            if (wantsPresentation && /present|slide|deck|ppt/.test(typeStr)) { s += 8; reasons.push('matches "presentation" hint'); }
            if (wantsReport && /report/.test(typeStr)) { s += 6; reasons.push('matches "report" hint'); }
            if (wantsData && /data|csv|xls/.test(typeStr)) { s += 6; reasons.push('matches "data" hint'); }
            // Recency boost (scaled — newest doc gets ~5 points, decays linearly over 180d)
            const t = row.date ? new Date(row.date).getTime() : 0;
            if (t) {
                const ageDays = Math.max(0, (now - t) / (1000 * 3600 * 24));
                const recencyPts = Math.max(0, 5 - (ageDays / 36));
                s += recencyPts;
                if (wantsLatest) s += recencyPts; // double-weight when user asked for latest
            }
            // No object key = can't actually read — penalize
            if (!row.r2_object_key) { s -= 6; reasons.push('no stored object'); }
            return { s, reasons };
        };

        const scored = [];
        for (const r of subRows) {
            const sc = score(r, 'submission');
            scored.push({
                id: `sub:${r.id}`,
                title: r.title,
                type: r.type,
                category: r.type,
                date: r.date,
                uploader: r.uploader,
                project_id: r.project_id || null,
                project_name: r.project_name || null,
                source_kind: 'submission',
                score: sc.s,
                match_reason: sc.reasons.slice(0, 3).join('; ') || 'field match',
                can_read_content: !!r.r2_object_key && zoeDocCanReadContent(r.title, r.type)
            });
        }
        for (const r of grpRows) {
            const sc = score({ ...r, title: r.title || r.filename, type: r.file_type, date: r.created_at, uploader: r.uploaded_by }, 'group');
            scored.push({
                id: `grp:${r.id}`,
                title: r.title || r.filename,
                type: r.file_type,
                category: r.category,
                date: r.created_at,
                uploader: r.uploaded_by,
                project_id: null,
                project_name: null,
                source_kind: 'group_document',
                score: sc.s,
                match_reason: sc.reasons.slice(0, 3).join('; ') || 'field match',
                can_read_content: !!r.r2_object_key && zoeDocCanReadContent(r.filename, r.file_type)
            });
        }

        scored.sort((a, b) => b.score - a.score || new Date(b.date || 0) - new Date(a.date || 0));
        const top = scored.slice(0, 5);

        // Confidence buckets (for UI auto-read threshold):
        //   high: best score ≥ 15 AND (top gap ≥ 8 OR only one match)
        //   medium: best score ≥ 8
        //   low: otherwise
        let confidence = 'low';
        if (top.length > 0) {
            const best = top[0].score;
            const second = top[1] ? top[1].score : 0;
            if (best >= 15 && (top.length === 1 || (best - second) >= 8)) confidence = 'high';
            else if (best >= 8) confidence = 'medium';
        }

        res.json({
            query: rawQ,
            tokens,
            type_hints: {
                paper: wantsPaper, sop: wantsSop, presentation: wantsPresentation,
                report: wantsReport, data: wantsData, latest: wantsLatest
            },
            confidence,
            matches: top
        });
    } catch (err) {
        console.error('[ZOE-FIND] error:', err.message);
        res.status(500).json({ error: 'Failed to resolve document' });
    }
});

// GET /api/zoe/document/:id — metadata + extracted text for one document.
// :id is namespaced — `sub:<submission_id>` | `grp:<id>`. Legacy numeric
// IDs are treated as group_documents for back-compat.
app.get('/api/zoe/document/:id', requirePIRead, async (req, res) => {
    try {
        const raw = String(req.params.id || '').trim();
        let kind = 'submission';
        let key = raw;
        if (raw.startsWith('sub:')) { kind = 'submission'; key = raw.slice(4); }
        else if (raw.startsWith('grp:')) { kind = 'group_document'; key = raw.slice(4); }
        else if (/^\d+$/.test(raw)) { kind = 'group_document'; key = raw; }

        let meta = null;
        let r2Key = null;
        let filename = null;
        let fileType = null;

        if (kind === 'submission') {
            const wsId = req.session.user.workspace_id || DEFAULT_WORKSPACE_ID;
            const q = await pool.query(
                `SELECT s.submission_id, s.original_filename, s.file_type, s.status,
                        s.uploader_researcher_id, s.created_at, s.r2_object_key,
                        s.workspace_id
                        ${await hasRdProjectIdCol() ? ', s.rd_project_id' : ''}
                 FROM di_submissions s
                 WHERE s.submission_id = $1`,
                [key]
            );
            if (q.rows.length === 0) return res.status(404).json({ error: 'Document not found' });
            const row = q.rows[0];
            // Workspace scoping: enforce visibility
            if (row.workspace_id != null && wsId != null && Number(row.workspace_id) !== Number(wsId)) {
                return res.status(403).json({ error: 'Document outside workspace scope' });
            }
            let projectName = null;
            if (row.rd_project_id != null) {
                try {
                    const p = await pool.query(`SELECT title FROM rd_projects WHERE id = $1`, [row.rd_project_id]);
                    projectName = p.rows[0]?.title || null;
                } catch (_) {}
            }
            meta = {
                id: raw,
                title: row.original_filename,
                type: row.file_type,
                category: row.file_type,
                uploader: row.uploader_researcher_id,
                date: row.created_at,
                status: row.status,
                project_id: row.rd_project_id || null,
                project_name: projectName,
                source_kind: 'submission'
            };
            r2Key = row.r2_object_key;
            filename = row.original_filename;
            fileType = row.file_type;
        } else {
            const q = await pool.query(
                `SELECT id, title, category, description, filename, file_type, r2_object_key,
                        created_at, uploaded_by, is_active
                 FROM di_group_documents WHERE id = $1`,
                [key]
            );
            if (q.rows.length === 0) return res.status(404).json({ error: 'Document not found' });
            const row = q.rows[0];
            if (!row.is_active) return res.status(410).json({ error: 'Document no longer active' });
            meta = {
                id: raw,
                title: row.title || row.filename,
                type: row.file_type,
                category: row.category,
                uploader: row.uploaded_by,
                date: row.created_at,
                status: 'ACTIVE',
                project_id: null,
                project_name: null,
                source_kind: 'group_document',
                description: row.description || null
            };
            r2Key = row.r2_object_key;
            filename = row.filename;
            fileType = row.file_type;
        }

        // Graceful path: metadata-only if no object key
        if (!r2Key) {
            return res.json({
                ...meta,
                text_content: null,
                content_truncated: false,
                extraction_method: null,
                text_length: 0,
                notes: 'No stored object for this record — metadata only.'
            });
        }

        // Extract — bounded by ZOE_DOC_MAX_CHARS
        try {
            const normKey = typeof normalizeR2Key === 'function' ? normalizeR2Key(r2Key) : r2Key;
            const obj = await downloadFromR2(normKey);
            const buf = obj && (obj.Body || obj.body || obj) && Buffer.isBuffer(obj.Body) ? obj.Body
                        : Buffer.isBuffer(obj) ? obj
                        : Buffer.isBuffer(obj?.body) ? obj.body
                        : null;
            const buffer = buf || (obj?.Body ? Buffer.from(obj.Body) : null);
            if (!buffer) throw new Error('Empty buffer from storage');
            const out = await zoeExtractFromBuffer(buffer, fileType, filename);
            if (out && out.text != null) {
                return res.json({
                    ...meta,
                    text_content: out.text,
                    content_truncated: !!out.content_truncated,
                    extraction_method: out.extraction_method,
                    text_length: out.text.length,
                    pages: out.pages || null,
                    sheets: out.sheets || null,
                    notes: out.content_truncated
                        ? `Content truncated at ${ZOE_DOC_MAX_CHARS} characters — showing beginning of document.`
                        : null
                });
            }
            return res.json({
                ...meta,
                text_content: null,
                content_truncated: false,
                extraction_method: null,
                text_length: 0,
                notes: (out && out.error) ? `Extraction unavailable: ${out.error}` : 'Readable content unavailable for this format.'
            });
        } catch (err) {
            console.error('[ZOE-DOC] extract error:', err.message);
            return res.json({
                ...meta,
                text_content: null,
                content_truncated: false,
                extraction_method: null,
                text_length: 0,
                notes: `Extraction failed: ${err.message}`
            });
        }
    } catch (err) {
        console.error('[ZOE-DOC] get error:', err.message);
        res.status(500).json({ error: 'Failed to load document' });
    }
});

// 3) POST /api/zoe/analyze-file
app.post('/api/zoe/analyze-file', requirePI, upload.single('file'), async (req, res) => {
    try {
        if (!req.file) return res.status(400).json({ error: 'file required' });
        const allowed = ['application/pdf', 'text/csv', 'application/vnd.ms-excel', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', 'image/png', 'image/jpeg'];
        if (!allowed.includes(req.file.mimetype)) return res.status(400).json({ error: 'Unsupported file type' });
        const id = 'zoe_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
        const extracted = await zoeExtractFileText(req.file);
        let summary;
        if (extracted && extracted.text) {
            const preview = extracted.text.slice(0, 400).replace(/\s+/g, ' ').trim();
            const meta = extracted.pages ? `${extracted.pages} page(s)` : (extracted.sheets ? `sheets: ${extracted.sheets.join(', ')}` : '');
            summary = `Extracted ${extracted.text.length} chars${meta ? ' • ' + meta : ''}${extracted.truncated ? ' (truncated)' : ''}. Preview: ${preview}`;
        } else if (extracted && extracted.error) {
            summary = `Received ${req.file.originalname} (${Math.round(req.file.size / 1024)} KB). Text extraction failed: ${extracted.error}.`;
        } else {
            summary = `Received ${req.file.originalname} (${Math.round(req.file.size / 1024)} KB). This file type is kept for visual reference; no text extraction performed.`;
        }
        // TODO: persist to R2 for durable review.
        zoeFileStore.set(id, {
            id, name: req.file.originalname, mime: req.file.mimetype,
            size: req.file.size, buffer: req.file.buffer, summary,
            extractedText: extracted && extracted.text ? extracted.text : null,
            uploadedAt: Date.now(), ownerUserId: req.session.user.id,
        });
        // Evict oldest if over 50 entries
        if (zoeFileStore.size > 50) {
            const oldest = [...zoeFileStore.entries()].sort((a, b) => a[1].uploadedAt - b[1].uploadedAt)[0];
            if (oldest) zoeFileStore.delete(oldest[0]);
        }
        res.json({ fileId: id, summary });
    } catch (err) {
        console.error('[ZOE] analyze-file error:', err.message);
        res.status(500).json({ error: 'Analyze failed' });
    }
});

// 4) POST /api/zoe/work-action
app.post('/api/zoe/work-action', requirePI, async (req, res) => {
    try {
        const { kind, selectedFileId, glpContext } = req.body || {};
        const allowed = ['supervision_note', 'project_summary', 'approval_suggestion', 'researcher_feedback', 'weekly_summary', 'meeting_brief'];
        if (!allowed.includes(kind)) return res.status(400).json({ error: 'unsupported action' });
        const prompt = `Prepare a ${kind.replace(/_/g, ' ')} draft for the PI based on current portal context. Return plain text only; do not claim execution.`;
        const out = await zoeHandleChat({
            userId: req.session.user.id,
            workspaceId: req.session.user.workspace_id || DEFAULT_WORKSPACE_ID,
            message: prompt, mode: 'work', selectedFileId, glpContext,
        });
        // TODO: persist drafts into a zoe_drafts table for audit once schema is added.
        res.json({ draft: out.reply, kind });
    } catch (err) {
        console.error('[ZOE] work-action error:', err.message);
        res.status(500).json({ error: 'Work action failed' });
    }
});

// 5) POST /api/zoe/glp-context — cache current GLP Vision file context in session
app.post('/api/zoe/glp-context', requirePI, async (req, res) => {
    try {
        const ctx = req.body || {};
        req.session.zoeGlpContext = {
            submissionId: ctx.submissionId || null,
            fileName: ctx.fileName || null,
            status: ctx.status || null,
            at: Date.now(),
        };
        res.json({ ok: true, glpContext: req.session.zoeGlpContext });
    } catch (err) {
        res.status(500).json({ error: 'Failed to cache GLP context' });
    }
});

// PI-only debug: report computed OpenClaw upstream config (no secrets).
app.get('/api/zoe/debug-openclaw', requirePIRead, (req, res) => {
    const baseUrl = process.env.OPENCLAW_BASE_URL || null;
    let chatPath = process.env.OPENCLAW_CHAT_PATH || '/v1/chat/completions';
    if (chatPath && !chatPath.startsWith('/')) chatPath = '/' + chatPath;
    const computed = baseUrl ? (baseUrl.replace(/\/$/, '') + chatPath) : null;
    res.json({
        openclaw_base_url: baseUrl,
        openclaw_chat_path: chatPath,
        computed_upstream_url: computed,
        openclaw_auth_header: process.env.OPENCLAW_AUTH_HEADER || 'Authorization',
        has_openclaw_api_key: !!process.env.OPENCLAW_API_KEY,
        openclaw_model_effective: process.env.OPENCLAW_MODEL || 'default',
        openclaw_timeout_ms_effective: parseInt(process.env.OPENCLAW_TIMEOUT_MS || '60000', 10),
        openclaw_max_tokens_effective: process.env.OPENCLAW_MAX_TOKENS ? parseInt(process.env.OPENCLAW_MAX_TOKENS, 10) : null,
        openclaw_temperature_effective: process.env.OPENCLAW_TEMPERATURE ? parseFloat(process.env.OPENCLAW_TEMPERATURE) : null,
    });
});

// PI-only one-shot connectivity test: minimal POST to the configured URL.
// Returns status code and a short snippet of the response body. No secrets exposed.
app.get('/api/zoe/test-openclaw', requirePIRead, async (req, res) => {
    const baseUrl = process.env.OPENCLAW_BASE_URL;
    if (!baseUrl) return res.status(400).json({ error: 'OPENCLAW_BASE_URL not set' });
    let chatPath = process.env.OPENCLAW_CHAT_PATH || '/v1/chat/completions';
    if (!chatPath.startsWith('/')) chatPath = '/' + chatPath;
    const url = baseUrl.replace(/\/$/, '') + chatPath;
    const headers = { 'Content-Type': 'application/json' };
    if (process.env.OPENCLAW_API_KEY) {
        const authHeader = process.env.OPENCLAW_AUTH_HEADER || 'Authorization';
        const val = authHeader.toLowerCase() === 'authorization'
            ? 'Bearer ' + process.env.OPENCLAW_API_KEY
            : process.env.OPENCLAW_API_KEY;
        headers[authHeader] = val;
    }
    const body = {
        model: process.env.OPENCLAW_MODEL || 'default',
        messages: [{ role: 'user', content: 'ping' }],
        max_tokens: 8,
    };
    const timeoutMs = 20000;
    const fetchPromise = fetch(url, { method: 'POST', headers, body: JSON.stringify(body) });
    const timeoutPromise = new Promise((_, reject) =>
        setTimeout(() => reject(new Error('TIMEOUT_' + timeoutMs + 'ms')), timeoutMs)
    );
    try {
        const r = await Promise.race([fetchPromise, timeoutPromise]);
        const text = await r.text();
        res.json({
            url,
            request_model_used: body.model,
            request_timeout_ms: timeoutMs,
            status: r.status,
            statusText: r.statusText,
            content_type: r.headers.get('content-type') || null,
            body_snippet: (text || '').slice(0, 200),
            ok: r.ok,
        });
    } catch (err) {
        const msg = err && err.message ? err.message : String(err);
        const isTimeout = msg.startsWith('TIMEOUT_');
        res.status(isTimeout ? 504 : 502).json({ url, request_model_used: body.model, request_timeout_ms: timeoutMs, error: msg, timeout: isTimeout });
    }
});

// =====================================================
// TELEGRAM WEBHOOK — remote Zoe interface
// =====================================================
async function telegramSendMessage(chatId, text) {
    const token = process.env.TELEGRAM_BOT_TOKEN;
    if (!token) return;
    try {
        await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ chat_id: chatId, text: String(text || '').slice(0, 3800) }),
        });
    } catch (err) {
        console.error('[TELEGRAM] send error:', err.message);
    }
}

app.post('/api/telegram/webhook', async (req, res) => {
    try {
        const secret = process.env.TELEGRAM_WEBHOOK_SECRET;
        if (secret && req.query.secret !== secret) return res.status(403).json({ error: 'forbidden' });
        const update = req.body || {};
        const msg = update.message || update.edited_message;
        if (!msg || !msg.text) return res.json({ ok: true });
        const fromId = String(msg.from && msg.from.id);
        const allowed = (process.env.TELEGRAM_ALLOWED_USER_ID || '').split(',').map(s => s.trim()).filter(Boolean);
        if (!allowed.includes(fromId)) {
            await telegramSendMessage(msg.chat.id, 'Access denied.');
            return res.json({ ok: true });
        }
        let text = msg.text.trim();
        let mode = 'read';
        if (/^\/work\b/i.test(text)) { mode = 'work'; text = text.replace(/^\/work\b\s*/i, ''); }
        else if (/^\/glp\b/i.test(text)) { text = 'Summarize current pending GLP items. ' + text.replace(/^\/glp\b\s*/i, ''); }
        else if (/^\/activity\b/i.test(text)) { text = 'Summarize recent portal activity. ' + text.replace(/^\/activity\b\s*/i, ''); }
        else if (/^\/project\b/i.test(text)) { text = 'Give a project overview for: ' + text.replace(/^\/project\b\s*/i, ''); }
        else if (/^\/researcher\b/i.test(text)) { text = 'Summarize this researcher: ' + text.replace(/^\/researcher\b\s*/i, ''); }
        else if (/^\/file\b/i.test(text)) { text = 'Find file matching: ' + text.replace(/^\/file\b\s*/i, ''); }

        // TODO: map Telegram fromId -> PI user_id via a dedicated mapping table.
        const out = await zoeHandleChat({
            userId: null,
            workspaceId: DEFAULT_WORKSPACE_ID,
            message: text, mode,
            selectedFileId: null, glpContext: null,
        });
        await telegramSendMessage(msg.chat.id, out.reply);
        res.json({ ok: true });
    } catch (err) {
        console.error('[TELEGRAM] webhook error:', err.message);
        res.json({ ok: true });
    }
});

